export interface ScoreEntry {
  taskId: TaskId;
  date: string;
  correct: number;
  total: number;
  pct: number;
  elapsedSeconds?: number;
  questionFile?: string;
}

const STORAGE_KEY = "score-history";

function readScores(): ScoreEntry[] {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    return raw ? (JSON.parse(raw) as ScoreEntry[]) : [];
  } catch {
    return [];
  }
}

function writeScores(entries: ScoreEntry[]) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(entries));
}

export function useScoreHistory() {
  const saveScore = useCallback(
    async (
      taskId: TaskId,
      correct: number,
      total: number,
      elapsedSeconds = 0,
      questionFile?: string,
    ) => {
      if (total === 0) return;
      const entry: ScoreEntry = {
        taskId,
        date: new Date().toISOString(),
        correct,
        total,
        pct: Math.round((correct / total) * 100),
        elapsedSeconds: Math.max(0, Math.floor(elapsedSeconds)),
      };
      if (questionFile) {
        entry.questionFile = questionFile;
      }
      const entries = readScores();
      entries.push(entry);
      writeScores(entries);
    },
    [],
  );

  const getAll = useCallback(async (): Promise<ScoreEntry[]> => {
    return readScores();
  }, []);

  const clearAll = useCallback(async () => {
    localStorage.removeItem(STORAGE_KEY);
  }, []);

  return { saveScore, getAll, clearAll };
}

import { useState, useCallback } from "react";
import {
  fetchQuestionByFileWithMeta,
  fetchQuestionByNumberWithMeta,
  fetchRandomQuestionWithMeta,
} from "../lib/questions";

/**
 * Hook that loads a random pre-generated question file for a given task.
 * Call `load()` to fetch a new random question from public/questions/<taskPath>/.
 */
export function useQuestion<T>(taskPath: string) {
  const [data, setData] = useState<T | null>(null);
  const [file, setFile] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const result = await fetchRandomQuestionWithMeta<T>(taskPath);
      setData(result.data);
      setFile(result.file);
    } catch (e) {
      setData(null);
      setFile(null);
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setLoading(false);
    }
  }, [taskPath]);

  const loadByFile = useCallback(
    async (questionFile: string) => {
      setLoading(true);
      setError(null);
      try {
        const result = await fetchQuestionByFileWithMeta<T>(
          taskPath,
          questionFile,
        );
        setData(result.data);
        setFile(result.file);
      } catch (e) {
        setData(null);
        setFile(null);
        setError(e instanceof Error ? e.message : String(e));
      } finally {
        setLoading(false);
      }
    },
    [taskPath],
  );

  const loadByQuestionNumber = useCallback(
    async (questionNumber: number) => {
      setLoading(true);
      setError(null);
      try {
        const result = await fetchQuestionByNumberWithMeta<T>(
          taskPath,
          questionNumber,
        );
        setData(result.data);
        setFile(result.file);
      } catch (e) {
        setData(null);
        setFile(null);
        setError(e instanceof Error ? e.message : String(e));
      } finally {
        setLoading(false);
      }
    },
    [taskPath],
  );

  return { data, file, loading, error, load, loadByFile, loadByQuestionNumber };
}

/**
 * Questions loader — fetches pre-generated JSON problem files from public/questions/.
 *
 * Problem files are generated by AI (Claude Code / Claude agent) and saved as JSON.
 * The frontend only reads these files; no network/API calls to AI are made at runtime.
 *
 * Directory structure (under public/questions/):
 *   toefl/reading/complete-words/      *.json
 *   toefl/reading/daily-life/          *.json
 *   toefl/reading/academic/            *.json
 *   toefl/writing/build-sentence/      *.json
 *   toefl/writing/email/               *.json
 *   toefl/writing/discussion/          *.json
 *   toefl/speaking/listen-repeat/      *.json
 *   toefl/speaking/interview/          *.json
 *   toeic/part5/                       *.json
 *   toeic/part6/                       *.json
 *   toeic/part7/                       *.json
 *
 * Each directory has an index.json listing available files:
 *   { "files": ["001.json", "002.json", ...] }
 */

export interface QuestionIndex {
  files: string[];
}

export interface LoadedQuestion<T> {
  data: T;
  file: string;
}

export interface QuestionFileEntry {
  file: string;
  number: number;
}

export async function fetchQuestionIndex(
  taskPath: string,
): Promise<QuestionIndex> {
  const res = await fetch(`/questions/${taskPath}/index.json`);
  if (!res.ok)
    throw new Error(`No questions found for ${taskPath}. Generate some first!`);
  return res.json();
}

export async function fetchRandomQuestion<T>(taskPath: string): Promise<T> {
  const loaded = await fetchRandomQuestionWithMeta<T>(taskPath);
  return loaded.data;
}

export async function listQuestionFiles(
  taskPath: string,
): Promise<QuestionFileEntry[]> {
  const index = await fetchQuestionIndex(taskPath);
  return index.files
    .map((file) => {
      const basename = file.replace(/\.[^.]+$/, "");
      if (!/^\d+$/.test(basename)) {
        throw new Error(
          `Question file "${file}" in ${taskPath} must use numeric filename like 001.json.`,
        );
      }
      return {
        file,
        number: Number.parseInt(basename, 10),
      };
    })
    .sort((a, b) => a.number - b.number || a.file.localeCompare(b.file));
}

export async function fetchQuestionByFileWithMeta<T>(
  taskPath: string,
  file: string,
): Promise<LoadedQuestion<T>> {
  const res = await fetch(`/questions/${taskPath}/${file}`);
  if (!res.ok) throw new Error(`Failed to load question file: ${file}`);
  const data = (await res.json()) as T;
  return { data, file };
}

export async function fetchQuestionByNumberWithMeta<T>(
  taskPath: string,
  questionNumber: number,
): Promise<LoadedQuestion<T>> {
  const files = await listQuestionFiles(taskPath);
  const selected = files.find((item) => item.number === questionNumber);
  if (!selected) {
    throw new Error(
      `Question ${questionNumber} not found in ${taskPath}. Generate or register it first.`,
    );
  }
  return fetchQuestionByFileWithMeta<T>(taskPath, selected.file);
}

export async function fetchRandomQuestionWithMeta<T>(
  taskPath: string,
): Promise<LoadedQuestion<T>> {
  const files = await listQuestionFiles(taskPath);
  if (files.length === 0) {
    throw new Error(`No question files in ${taskPath}. Generate some first!`);
  }
  const selected = files[Math.floor(Math.random() * files.length)];
  return fetchQuestionByFileWithMeta<T>(taskPath, selected.file);
}

export async function fetchAllQuestions<T>(taskPath: string): Promise<T[]> {
  const index = await fetchQuestionIndex(taskPath);
  const results = await Promise.all(
    index.files.map(async (file) => {
      const res = await fetch(`/questions/${taskPath}/${file}`);
      if (!res.ok) throw new Error(`Failed to load: ${file}`);
      return res.json() as Promise<T>;
    }),
  );
  return results;
}

export interface SaveAnswerPayload {
  taskId: string;
  problemId: string;
  response: string;
  question?: unknown;
}

interface SaveAnswerResponse {
  answerId: string;
}

export interface AnswerEntry {
  answerId: string;
  taskId: string;
  problemId: string;
  response: string;
  date: string;
}

const DRAFT_KEY_PREFIX = "answer-draft:";
const ANSWERS_STORAGE_KEY = "answer-history";

export function buildProblemId(
  taskId: string,
  sourceFile: string,
  subQuestionId?: string,
) {
  const fileId = sourceFile.replace(/\.json$/i, "");
  if (subQuestionId) {
    return `${taskId}/${fileId}#${subQuestionId}`;
  }
  return `${taskId}/${fileId}`;
}

export function buildDraftKey(problemId: string) {
  return `${DRAFT_KEY_PREFIX}${problemId}`;
}

export function loadDraft(problemId: string) {
  const value = localStorage.getItem(buildDraftKey(problemId));
  return value ?? "";
}

export function saveDraft(problemId: string, text: string) {
  const key = buildDraftKey(problemId);
  if (text.trim().length === 0) {
    localStorage.removeItem(key);
    return;
  }
  localStorage.setItem(key, text);
}

export function clearDraft(problemId: string) {
  localStorage.removeItem(buildDraftKey(problemId));
}

function readAnswerHistory(): AnswerEntry[] {
  try {
    const raw = localStorage.getItem(ANSWERS_STORAGE_KEY);
    return raw ? (JSON.parse(raw) as AnswerEntry[]) : [];
  } catch {
    return [];
  }
}

function writeAnswerHistory(entries: AnswerEntry[]) {
  localStorage.setItem(ANSWERS_STORAGE_KEY, JSON.stringify(entries));
}

export async function saveAnswerSubmission(payload: SaveAnswerPayload) {
  const entries = readAnswerHistory();
  const answerId = `ans-${Date.now()}`;
  const entry: AnswerEntry = {
    answerId,
    taskId: payload.taskId,
    problemId: payload.problemId,
    response: payload.response,
    date: new Date().toISOString(),
  };
  entries.push(entry);
  writeAnswerHistory(entries);
  return { answerId } as SaveAnswerResponse;
}

export function getAllAnswers(): AnswerEntry[] {
  return readAnswerHistory().slice().reverse();
}

export function buildGradingMessage(problemId: string, answerId: string) {
  return `I completed problem ${problemId}. My answer ID is ${answerId}. Please grade it.`;
}

export async function copyText(text: string) {
  if (typeof navigator.clipboard?.writeText !== "function") {
    return false;
  }
  await navigator.clipboard.writeText(text);
  return true;
}

import { useEffect, useRef, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { SectionHeader } from "../../../components/layout/SectionHeader";
import { BackButton } from "../../../components/ui/BackButton";
import { Button } from "../../../components/ui/Button";
import { LoadingSpinner } from "../../../components/ui/LoadingSpinner";
import { FloatingElapsedTimer } from "../../../components/ui/FloatingElapsedTimer";
import { useElapsedTimer } from "../../../hooks/useElapsedTimer";
import { useQuestion } from "../../../hooks/useQuestion";
import { useScoreHistory } from "../../../hooks/useScoreHistory";
import {
  findAnswerPosition,
  getExpectedSuffix,
  type CompleteWordsItem,
} from "./completeWords";
import styles from "./CompleteWordsPage.module.css";

interface ProblemData {
  paragraph: string;
  items: CompleteWordsItem[];
}

export function CompleteWordsPage() {
  const navigate = useNavigate();
  const { questionNumber } = useParams<{ questionNumber: string }>();
  const { data, file, loading, error, loadByQuestionNumber } =
    useQuestion<ProblemData>("toefl/reading/complete-words");
  const { saveScore } = useScoreHistory();
  const {
    display,
    elapsedSeconds,
    running,
    start,
    stop,
    reset: resetTimer,
  } = useElapsedTimer();
  const [answers, setAnswers] = useState<string[]>([]);
  const [submitted, setSubmitted] = useState(false);
  const [score, setScore] = useState<{ correct: number; total: number } | null>(
    null,
  );
  const [focusedIdx, setFocusedIdx] = useState<number | null>(null);
  const inputRefs = useRef<Array<HTMLTextAreaElement | null>>([]);

  const parsedQuestionNumber = Number.parseInt(questionNumber ?? "", 10);
  const hasValidQuestionNumber =
    Number.isInteger(parsedQuestionNumber) && parsedQuestionNumber > 0;

  useEffect(() => {
    if (!hasValidQuestionNumber) return;
    loadByQuestionNumber(parsedQuestionNumber);
  }, [hasValidQuestionNumber, loadByQuestionNumber, parsedQuestionNumber]);

  useEffect(() => {
    if (data) {
      setAnswers(data.items.map(() => ""));
      setSubmitted(false);
      setScore(null);
      setFocusedIdx(null);
      inputRefs.current = [];
    }
  }, [data]);

  useEffect(() => {
    if (data && !loading && !submitted && !running && elapsedSeconds === 0) {
      start();
    }
  }, [data, loading, submitted, running, elapsedSeconds, start]);

  useEffect(() => {
    if (focusedIdx !== null) {
      autoResize(focusedIdx);
    }
  }, [answers, focusedIdx]);

  const autoResize = (idx: number) => {
    const el = inputRefs.current[idx];
    if (!el) return;
    el.style.height = "auto";
    el.style.height = `${el.scrollHeight}px`;
  };

  const findNextBlank = (fromIdx: number): number | null => {
    for (let i = fromIdx + 1; i < (data?.items.length ?? 0); i++) {
      if (getExpectedSuffix(data!.items[i]).length > 0) return i;
    }
    return null;
  };

  const findPrevBlank = (fromIdx: number): number | null => {
    for (let i = fromIdx - 1; i >= 0; i--) {
      if (getExpectedSuffix(data!.items[i]).length > 0) return i;
    }
    return null;
  };

  const handleSubmit = () => {
    if (!data) return;
    const sessionSeconds = stop();
    let correct = 0;
    data.items.forEach((item, i) => {
      const expectedSuffix = getExpectedSuffix(item);
      if (answers[i].toLowerCase() === expectedSuffix.toLowerCase()) correct++;
    });
    setScore({ correct, total: data.items.length });
    setSubmitted(true);
    setFocusedIdx(null);
    saveScore(
      "toefl/reading/complete-words",
      correct,
      data.items.length,
      sessionSeconds,
      file ?? undefined,
    );
  };

  const handleBackToList = () => {
    resetTimer();
    navigate("/toefl/reading/complete-words");
  };

  const handleAnswerChange = (idx: number, value: string) => {
    setAnswers((prev) => {
      const next = [...prev];
      next[idx] = value;
      return next;
    });
  };

  const handleKeyDown = (idx: number, e: React.KeyboardEvent) => {
    if (!data) return;
    const expectedLen = getExpectedSuffix(data.items[idx]).length;
    if (expectedLen === 0) return;

    if (e.key === "Tab" && !e.shiftKey) {
      e.preventDefault();
      const nextIdx = findNextBlank(idx);
      if (nextIdx !== null) {
        setFocusedIdx(nextIdx);
        requestAnimationFrame(() => {
          inputRefs.current[nextIdx]?.focus();
          inputRefs.current[nextIdx]?.setSelectionRange(
            answers[nextIdx]?.length ?? 0,
            answers[nextIdx]?.length ?? 0,
          );
        });
      }
    } else if (e.key === "Tab" && e.shiftKey) {
      e.preventDefault();
      const prevIdx = findPrevBlank(idx);
      if (prevIdx !== null) {
        setFocusedIdx(prevIdx);
        requestAnimationFrame(() => {
          inputRefs.current[prevIdx]?.focus();
          inputRefs.current[prevIdx]?.setSelectionRange(
            answers[prevIdx]?.length ?? 0,
            answers[prevIdx]?.length ?? 0,
          );
        });
      }
    } else if (e.key === "Enter") {
      e.preventDefault();
      const nextIdx = findNextBlank(idx);
      if (nextIdx !== null) {
        setFocusedIdx(nextIdx);
        requestAnimationFrame(() => {
          inputRefs.current[nextIdx]?.focus();
          inputRefs.current[nextIdx]?.setSelectionRange(
            answers[nextIdx]?.length ?? 0,
            answers[nextIdx]?.length ?? 0,
          );
        });
      }
    }
  };

  const renderParagraph = () => {
    if (!data) return null;
    const text = data.paragraph;
    const parts: React.ReactNode[] = [];
    const usedStarts = new Set<number>();
    let lastIndex = 0;

    for (const [itemIdx, item] of data.items.entries()) {
      const answer = item.answer.trim();
      const pos = findAnswerPosition(text, answer, lastIndex, usedStarts);
      if (pos === -1) {
        console.warn(`Could not locate answer in paragraph: ${answer}`);
        continue;
      }

      usedStarts.add(pos);
      const expectedSuffix = getExpectedSuffix(item);
      const userInput = answers[itemIdx] ?? "";
      const isCorrect =
        submitted && userInput.toLowerCase() === expectedSuffix.toLowerCase();
      const isWrong = submitted && !isCorrect;
      const isFocused = focusedIdx === itemIdx;

      parts.push(<span key={`t${itemIdx}`}>{text.slice(lastIndex, pos)}</span>);

      if (expectedSuffix.length > 0) {
        parts.push(
          <span
            key={`inp${itemIdx}`}
            className={[
              styles.blankWrapper,
              isFocused ? styles.blankFocused : "",
              submitted
                ? isCorrect
                  ? styles.blankCorrect
                  : styles.blankWrong
                : "",
            ].join(" ")}
          >
            <span className={styles.hint}>{item.hint}</span>
            <textarea
              ref={(el) => {
                inputRefs.current[itemIdx] = el;
              }}
              className={styles.blankInput}
              value={userInput}
              onChange={(e) => handleAnswerChange(itemIdx, e.target.value)}
              onFocus={() => setFocusedIdx(itemIdx)}
              onBlur={() => setFocusedIdx(null)}
              onKeyDown={(e) => handleKeyDown(itemIdx, e)}
              style={{ width: `${Math.max(expectedSuffix.length, 1)}ch` }}
              rows={1}
              maxLength={expectedSuffix.length * 2}
              autoComplete="off"
              spellCheck={false}
              disabled={submitted}
              aria-label={`Blank ${itemIdx + 1}`}
            />
          </span>,
        );
        if (isWrong) {
          parts.push(
            <span key={`hint${itemIdx}`} className={styles.correctHint}>
              {item.answer}
            </span>,
          );
        }
      } else {
        parts.push(
          <span key={`inp${itemIdx}`} className={styles.hint}>
            {item.hint}
          </span>,
        );
      }

      lastIndex = pos + answer.length;
    }

    parts.push(<span key="tail">{text.slice(lastIndex)}</span>);
    return parts;
  };

  const hasIncompleteAnswers =
    !data ||
    answers.length !== data.items.length ||
    answers.some((ans, idx) => {
      const expectedLength = getExpectedSuffix(data.items[idx]).length;
      return expectedLength > 0 && !ans.trim();
    });

  return (
    <div>
      {(running || elapsedSeconds > 0) && (
        <FloatingElapsedTimer display={display} running={running} />
      )}

      <SectionHeader
        title="Complete the Words"
        subtitle="Type only the missing continuation after the visible prefix. Tab / Enter to move between blanks."
        backTo="/toefl"
      />

      <div className={styles.topBar}>
        <Button
          variant="secondary"
          size="sm"
          onClick={handleBackToList}
          disabled={loading}
        >
          Question List
        </Button>
      </div>

      {loading && <LoadingSpinner message="Loading question..." />}
      {error && (
        <div className={styles.error}>
          <p>{error}</p>
          <p className={styles.errorHint}>
            Generate question JSON with an AI agent and save it under
            questions/toefl/reading/complete-words/.
          </p>
        </div>
      )}
      {!hasValidQuestionNumber && (
        <div className={styles.error}>
          <p>Invalid question number in URL.</p>
        </div>
      )}

      {data && !loading && hasValidQuestionNumber && (
        <>
          <div className={styles.paragraph}>{renderParagraph()}</div>

          {!submitted ? (
            <Button onClick={handleSubmit} disabled={hasIncompleteAnswers}>
              Check Answers
            </Button>
          ) : (
            <div className={styles.result}>
              <div className={styles.scoreBox}>
                <span className={styles.scoreNum}>{score?.correct}</span>
                <span className={styles.scoreDen}>/{score?.total}</span>
                <span className={styles.scorePct}>
                  (
                  {Math.round(
                    ((score?.correct ?? 0) / (score?.total ?? 1)) * 100,
                  )}
                  %)
                </span>
              </div>
              <BackButton onClick={handleBackToList} />
            </div>
          )}
        </>
      )}
    </div>
  );
}

import { useEffect, useRef } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { SectionHeader } from "../../../components/layout/SectionHeader";
import { Button } from "../../../components/ui/Button";
import { LoadingSpinner } from "../../../components/ui/LoadingSpinner";
import { FeedbackPanel } from "../../../components/ui/FeedbackPanel";
import { FloatingElapsedTimer } from "../../../components/ui/FloatingElapsedTimer";
import { useElapsedTimer } from "../../../hooks/useElapsedTimer";
import { useQuestion } from "../../../hooks/useQuestion";
import { useScoreHistory } from "../../../hooks/useScoreHistory";
import { useState } from "react";
import styles from "./ReadDailyLifePage.module.css";

interface Question {
  id: string;
  stem: string;
  options: string[];
  correctIndex: number;
  type: string;
  explanation: string;
}

interface TextBlock {
  id: string;
  textType: string;
  content: string;
  questions: Question[];
}

interface ProblemData {
  texts: TextBlock[];
}

const TYPE_LABELS: Record<string, string> = {
  factual: "Factual",
  inference: "Inference",
  purpose: "Purpose",
  vocabulary: "Vocabulary",
};

function cleanOptionText(text: string): string {
  return text.replace(/^[A-Da-d][.)]\s*/, "");
}

export function ReadDailyLifePage() {
  const navigate = useNavigate();
  const { questionNumber } = useParams<{ questionNumber: string }>();
  const { data, file, loading, error, loadByQuestionNumber } =
    useQuestion<ProblemData>("toefl/reading/daily-life");
  const { saveScore } = useScoreHistory();
  const {
    display,
    elapsedSeconds,
    running,
    start,
    stop,
    reset: resetTimer,
  } = useElapsedTimer();
  const [answers, setAnswers] = useState<Record<string, number>>({});
  const [graded, setGraded] = useState(false);
  const sessionFileRef = useRef<string | null>(null);

  const parsedQuestionNumber = Number.parseInt(questionNumber ?? "", 10);
  const hasValidQuestionNumber =
    Number.isInteger(parsedQuestionNumber) && parsedQuestionNumber > 0;

  useEffect(() => {
    if (!hasValidQuestionNumber) return;
    sessionFileRef.current = null;
    loadByQuestionNumber(parsedQuestionNumber);
  }, [hasValidQuestionNumber, loadByQuestionNumber, parsedQuestionNumber]);

  useEffect(() => {
    if (file && !sessionFileRef.current) {
      sessionFileRef.current = file;
    }
  }, [file]);

  useEffect(() => {
    if (data && !loading && !graded && !running && elapsedSeconds === 0) {
      start();
    }
  }, [data, loading, graded, running, elapsedSeconds, start]);

  // Flatten questions across all texts so we can number them globally.
  const allQ: { text: TextBlock; question: Question }[] = [];
  if (data) {
    data.texts.forEach((t) =>
      t.questions.forEach((q) => allQ.push({ text: t, question: q })),
    );
  }

  const totalQ = allQ.length;
  const answeredCount = Object.keys(answers).length;
  const allAnswered = totalQ > 0 && answeredCount === totalQ;

  const correctCount = allQ.filter(
    ({ question }) => answers[question.id] === question.correctIndex,
  ).length;

  const handleSelect = (questionId: string, optionIndex: number) => {
    if (!graded) {
      setAnswers((s) => ({ ...s, [questionId]: optionIndex }));
    }
  };

  const handleSubmit = () => {
    const sessionSeconds = stop();
    saveScore(
      "toefl/reading/daily-life",
      correctCount,
      totalQ,
      sessionSeconds,
      sessionFileRef.current ?? file ?? undefined,
    );
    setGraded(true);
  };

  const handleRestart = () => {
    resetTimer();
    navigate("/toefl/reading/daily-life");
  };

  return (
    <div>
      {(running || elapsedSeconds > 0) && (
        <FloatingElapsedTimer display={display} running={running} />
      )}

      <SectionHeader
        title="Read in Daily Life"
        subtitle="Read everyday texts and answer all questions."
        backTo="/toefl"
        current={answeredCount}
        total={totalQ}
      />

      <div className={styles.topBar}>
        <Button
          variant="secondary"
          size="sm"
          onClick={() => navigate("/toefl/reading/daily-life")}
          disabled={loading}
        >
          Question List
        </Button>
      </div>

      {!hasValidQuestionNumber && (
        <div className={styles.error}>
          <p>Invalid question number in URL.</p>
        </div>
      )}

      {loading && <LoadingSpinner message="Loading question..." />}
      {error && (
        <div className={styles.error}>
          <p>{error}</p>
          <p className={styles.errorHint}>
            Add question JSON under questions/toefl/reading/daily-life/.
          </p>
        </div>
      )}

      {data && !loading && hasValidQuestionNumber && (
        <>
          {graded && (
            <div className={styles.resultCard}>
              <h2 className={styles.resultTitle}>Result</h2>
              <div className={styles.resultModules}>
                <div className={styles.moduleResult}>
                  <span className={styles.moduleLabel}>Score</span>
                  <span className={styles.moduleScore}>
                    {correctCount}/{totalQ} (
                    {totalQ > 0 ? Math.round((correctCount / totalQ) * 100) : 0}
                    %)
                  </span>
                </div>
              </div>
              <Button size="lg" onClick={handleRestart}>
                Try Again
              </Button>
            </div>
          )}

          <div className={styles.texts}>
            {data.texts.map((text) => (
              <section key={text.id} className={styles.textSection}>
                <div className={styles.textCard}>
                  <div className={styles.textMeta}>{text.textType}</div>
                  <p className={styles.textContent}>{text.content}</p>
                </div>

                <div className={styles.questions}>
                  {text.questions.map((q) => {
                    const globalIdx = allQ.findIndex(
                      (item) => item.question.id === q.id,
                    );
                    const selected = answers[q.id];
                    return (
                      <div key={q.id} className={styles.qBlock}>
                        <div className={styles.qHeader}>
                          <span className={styles.qNum}>{globalIdx + 1}</span>
                          <span className={styles.qType}>
                            {TYPE_LABELS[q.type] ?? q.type}
                          </span>
                        </div>
                        <p className={styles.stem}>{q.stem}</p>
                        <div className={styles.options}>
                          {q.options.map((opt, i) => (
                            <button
                              key={i}
                              className={[
                                styles.option,
                                selected === i ? styles.selected : "",
                                graded && i === q.correctIndex
                                  ? styles.correctOpt
                                  : "",
                                graded && selected === i && i !== q.correctIndex
                                  ? styles.wrongOpt
                                  : "",
                              ].join(" ")}
                              onClick={() => handleSelect(q.id, i)}
                            >
                              <span className={styles.optLabel}>
                                {String.fromCharCode(65 + i)}
                              </span>
                              {cleanOptionText(opt)}
                            </button>
                          ))}
                        </div>
                        {graded && (
                          <FeedbackPanel
                            correct={selected === q.correctIndex}
                            explanation={q.explanation}
                            correctAnswer={`(${String.fromCharCode(
                              65 + q.correctIndex,
                            )}) ${cleanOptionText(q.options[q.correctIndex])}`}
                          />
                        )}
                      </div>
                    );
                  })}
                </div>
              </section>
            ))}
          </div>

          {!graded && allAnswered && (
            <div className={styles.submitRow}>
              <Button onClick={handleSubmit} size="lg">
                Submit
              </Button>
            </div>
          )}
        </>
      )}
    </div>
  );
}

import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { SectionHeader } from "../../../components/layout/SectionHeader";
import { BackButton } from "../../../components/ui/BackButton";
import { Button } from "../../../components/ui/Button";
import { LoadingSpinner } from "../../../components/ui/LoadingSpinner";
import { FeedbackPanel } from "../../../components/ui/FeedbackPanel";
import { FloatingElapsedTimer } from "../../../components/ui/FloatingElapsedTimer";
import { useElapsedTimer } from "../../../hooks/useElapsedTimer";
import { useQuestion } from "../../../hooks/useQuestion";
import { useScoreHistory } from "../../../hooks/useScoreHistory";
import styles from "./ReadAcademicPage.module.css";

interface Question {
  id: string;
  type: string;
  stem: string;
  options: string[];
  correctIndex: number;
  explanation: string;
}

interface ProblemData {
  passage: string;
  title: string;
  questions: Question[];
}

const TYPE_LABELS: Record<string, string> = {
  vocabulary: "Vocabulary",
  detail: "Detail",
  inference: "Inference",
  mainIdea: "Main Idea",
  paragraphRelation: "Paragraph Relation",
  importantIdea: "Important Idea",
  negativeFactual: "Negative Factual",
  rhetoricalPurpose: "Rhetorical Purpose",
  insertSentence: "Insert Sentence",
};

function cleanOptionText(text: string): string {
  return text.replace(/^[A-Da-d][.)]\s*/, "");
}

export function ReadAcademicPage() {
  const navigate = useNavigate();
  const { questionNumber } = useParams<{ questionNumber: string }>();
  const { data, file, loading, error, loadByQuestionNumber } =
    useQuestion<ProblemData>("toefl/reading/academic");
  const { saveScore } = useScoreHistory();
  const {
    display,
    elapsedSeconds,
    running,
    start,
    stop,
    reset: resetTimer,
  } = useElapsedTimer();
  const [answers, setAnswers] = useState<Record<string, number>>({});
  const [graded, setGraded] = useState(false);

  const parsedQuestionNumber = Number.parseInt(questionNumber ?? "", 10);
  const hasValidQuestionNumber =
    Number.isInteger(parsedQuestionNumber) && parsedQuestionNumber > 0;

  useEffect(() => {
    if (!hasValidQuestionNumber) return;
    loadByQuestionNumber(parsedQuestionNumber);
  }, [hasValidQuestionNumber, loadByQuestionNumber, parsedQuestionNumber]);

  useEffect(() => {
    if (data && !loading && !graded && !running && elapsedSeconds === 0) {
      start();
    }
  }, [data, loading, graded, running, elapsedSeconds, start]);

  const handleBackToList = () => {
    resetTimer();
    navigate("/toefl/reading/academic");
  };

  const handleSelect = (questionId: string, optionIndex: number) => {
    if (!graded) setAnswers((s) => ({ ...s, [questionId]: optionIndex }));
  };

  const handleSubmit = () => {
    const sessionSeconds = stop();
    if (data) {
      const s = data.questions.filter(
        (q) => answers[q.id] === q.correctIndex,
      ).length;
      saveScore(
        "toefl/reading/academic",
        s,
        data.questions.length,
        sessionSeconds,
        file ?? undefined,
      );
    }
    setGraded(true);
  };

  const totalQ = data?.questions.length ?? 0;
  const totalAnswered = Object.keys(answers).length;
  const allAnswered = totalQ > 0 && totalAnswered === totalQ;

  const score = data
    ? data.questions.filter((q) => answers[q.id] === q.correctIndex).length
    : 0;

  return (
    <div>
      {(running || elapsedSeconds > 0) && (
        <FloatingElapsedTimer display={display} running={running} />
      )}

      <SectionHeader
        title="Read an Academic Passage"
        subtitle="Read the academic passage and answer all questions."
        backTo="/toefl"
        current={totalAnswered}
        total={totalQ}
      />

      <div className={styles.topBar}>
        <Button
          variant="secondary"
          size="sm"
          onClick={handleBackToList}
          disabled={loading}
        >
          Question List
        </Button>
      </div>

      {loading && <LoadingSpinner message="Loading question..." />}
      {error && (
        <div className={styles.error}>
          <p>{error}</p>
          <p className={styles.errorHint}>
            Add question JSON under questions/toefl/reading/academic/.
          </p>
        </div>
      )}
      {!hasValidQuestionNumber && (
        <div className={styles.error}>
          <p>Invalid question number in URL.</p>
        </div>
      )}

      {data && !loading && hasValidQuestionNumber && (
        <>
          {graded && (
            <div className={styles.resultCard}>
              <h2>Section Complete</h2>
              <div className={styles.scoreBox}>
                <span className={styles.scoreNum}>{score}</span>
                <span className={styles.scoreDen}>/{totalQ}</span>
                <span className={styles.scorePct}>
                  ({Math.round((score / totalQ) * 100)}%)
                </span>
              </div>
              <BackButton onClick={handleBackToList} size="lg" />
            </div>
          )}

          <div className={styles.layout}>
            <div className={styles.passageCard}>
              <h2 className={styles.passageTitle}>{data.title}</h2>
              <p className={styles.passage}>{data.passage}</p>
            </div>

            <div className={styles.questions}>
              {data.questions.map((q, idx) => {
                const selected = answers[q.id];
                return (
                  <div key={q.id} className={styles.questionCard}>
                    <div className={styles.qHeader}>
                      <span className={styles.qNum}>{idx + 1}</span>
                      <span className={styles.qType}>
                        {TYPE_LABELS[q.type] ?? q.type}
                      </span>
                    </div>
                    <p className={styles.stem}>{q.stem}</p>
                    <div className={styles.options}>
                      {q.options.map((opt, i) => (
                        <button
                          key={i}
                          className={[
                            styles.option,
                            selected === i ? styles.selected : "",
                            graded && i === q.correctIndex
                              ? styles.correctOpt
                              : "",
                            graded && selected === i && i !== q.correctIndex
                              ? styles.wrongOpt
                              : "",
                          ].join(" ")}
                          onClick={() => handleSelect(q.id, i)}
                        >
                          <span className={styles.optLabel}>
                            {String.fromCharCode(65 + i)}
                          </span>
                          {cleanOptionText(opt)}
                        </button>
                      ))}
                    </div>
                    {graded && (
                      <FeedbackPanel
                        correct={selected === q.correctIndex}
                        explanation={q.explanation}
                        correctAnswer={`(${String.fromCharCode(
                          65 + q.correctIndex,
                        )}) ${cleanOptionText(q.options[q.correctIndex])}`}
                      />
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          {!graded && allAnswered && (
            <div className={styles.submitRow}>
              <Button onClick={handleSubmit} size="lg">
                Submit
              </Button>
            </div>
          )}
        </>
      )}
    </div>
  );
}

export interface CompleteWordsItem {
  index: number;
  hint: string;
  answer: string;
}

function escapeRegExp(text: string): string {
  return text.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

export function getExpectedSuffix(item: CompleteWordsItem): string {
  const answer = item.answer.trim();
  const hint = item.hint.trim();
  if (answer.toLowerCase().startsWith(hint.toLowerCase())) {
    return answer.slice(hint.length);
  }
  return answer;
}

export function getAnswerMatches(paragraph: string, answer: string) {
  const pattern = new RegExp(
    `(^|[^A-Za-z])(${escapeRegExp(answer.trim())})(?=[^A-Za-z]|$)`,
    "gi",
  );
  const matches: Array<{ start: number }> = [];

  for (const match of paragraph.matchAll(pattern)) {
    const fullMatch = match[0];
    const answerText = match[2];
    const fullStart = match.index ?? -1;
    if (fullStart === -1) continue;

    const prefixLength = fullMatch.length - answerText.length;
    const start = fullStart + prefixLength;
    matches.push({ start });
  }

  return matches;
}

export function findAnswerPosition(
  paragraph: string,
  answer: string,
  fromIndex: number,
  usedStarts: Set<number>,
): number {
  const matches = getAnswerMatches(paragraph, answer);
  for (const match of matches) {
    if (match.start >= fromIndex && !usedStarts.has(match.start)) {
      return match.start;
    }
  }

  for (const match of matches) {
    if (!usedStarts.has(match.start)) return match.start;
  }

  return -1;
}

