                  <span className={styles.studentTag}>{s.name}</span>
                  <p>{s.response}</p>
                </div>
              ))}
            </div>
          </div>

          {phase === "pre" && (
            <div className={styles.startCard}>
              <p>
                Press Start when ready. The 10-minute timer will begin. Write at
                least 100 words.
              </p>
              <Button size="lg" onClick={handleStart}>
                Start
              </Button>
            </div>
          )}

          {(phase === "writing" || phase === "submitted") && (
            <div className={styles.writingArea}>
              <div className={styles.writingHeader}>
                <Timer
                  display={timer.display}
                  isWarning={timer.isWarning}
                  isExpired={timer.isExpired}
                />
                <span
                  className={[
                    styles.wordCount,
                    meetsMinWords ? styles.ok : styles.notOk,
                  ].join(" ")}
                >
                  {wordCount} / {MIN_WORDS}+ words
                </span>
              </div>
              <textarea
                className={styles.textarea}
                value={userText}
                onChange={(e) => setUserText(e.target.value)}
                placeholder="Type your response here..."
                disabled={phase === "submitted"}
                rows={14}
              />
              {phase === "writing" && (
                <Button onClick={handleSubmit} disabled={!meetsMinWords}>
                  Submit
                  {!meetsMinWords
                    ? ` (${MIN_WORDS - wordCount} more words required)`
                    : ""}
                </Button>
              )}
            </div>
          )}

          {phase === "submitted" && (
            <div className={styles.feedbackSection}>
              <GradingRequestPanel
                saving={savingAnswer}
                error={saveError}
                message={gradingMessage}
                copied={copied}
                onCopy={() => {
                  void handleCopy();
                }}
              />
              <div className={styles.evalCard}>
                <h3>Evaluation Points</h3>
                <ul className={styles.evalList}>
                  {data.evaluationPoints.map((pt, i) => (
                    <li key={i}>{pt}</li>
                  ))}
                </ul>
              </div>
              <div className={styles.modelSection}>
                <Button
                  variant="secondary"
                  onClick={() => setShowModel((v) => !v)}
                >
                  {showModel ? "Hide Model Answer" : "Show Model Answer"}
                </Button>
                {showModel && (
                  <div className={styles.modelAnswer}>
                    <h3>Model Answer</h3>
                    <p>{data.modelAnswer}</p>
                  </div>
                )}
              </div>
              <BackButton onClick={handleBackToList} size="lg" />
            </div>
          )}
        </>
      )}
    </div>
  );
}

import { useState, useEffect, useRef, useCallback } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { SectionHeader } from "../../../components/layout/SectionHeader";
import { BackButton } from "../../../components/ui/BackButton";
import { Button } from "../../../components/ui/Button";
import { LoadingSpinner } from "../../../components/ui/LoadingSpinner";
import { ProgressBar } from "../../../components/ui/ProgressBar";
import { FloatingElapsedTimer } from "../../../components/ui/FloatingElapsedTimer";
import { SpeedControl } from "../../../components/ui/SpeedControl";
import { useElapsedTimer } from "../../../hooks/useElapsedTimer";
import { useQuestion } from "../../../hooks/useQuestion";
import { useScoreHistory } from "../../../hooks/useScoreHistory";
import { useTts } from "../../../hooks/useTts";
import { useSpeechRecognition } from "../../../hooks/useSpeechRecognition";
import {
  alignWords,
  countCorrectWords,
  countOriginalWords,
  type AlignedWord,
} from "./listenRepeat";
import styles from "./ListenRepeatPage.module.css";

interface Sentence {
  id: string;
  text: string;
  wordCount: number;
}
interface ProblemData {
  sentences: Sentence[];
}

function formatTime(seconds: number) {
  const m = Math.floor(seconds / 60);
  const s = Math.floor(seconds % 60);
  return `${m}:${String(s).padStart(2, "0")}`;
}

const DEFAULT_WORDS_PER_SECOND = 2.2;
const RECORDING_MULTIPLIER = 1.5;
const PROCESSING_DELAY_MS = 400;

type Phase =
  | "playing"
  | "ready"
  | "recording"
  | "processing"
  | "feedback"
  | "review";

function DiffLegend() {
  return (
    <div className={styles.legend}>
      <p className={styles.fbLabel}>How to read the answer</p>
      <div className={styles.legendItems}>
        <div className={styles.legendItem}>
          <span
            className={[styles.diffWord, styles.diffCorrect].join(" ")}
            title="Correctly spoken"
          >
            correct
          </span>
          <span className={styles.legendLabel}>Correctly spoken</span>
        </div>
        <div className={styles.legendItem}>
          <span
            className={[styles.diffWord, styles.diffWrong].join(" ")}
            title="Wrong word"
          >
            wrong
          </span>
          <span className={styles.legendLabel}>Wrong word</span>
        </div>
        <div className={styles.legendItem}>
          <span
            className={[
              styles.diffWord,
              styles.diffWrong,
              styles.diffMissing,
            ].join(" ")}
            title="Missing word"
          >
            ▪
          </span>
          <span className={styles.legendLabel}>Missing word</span>
        </div>
        <div className={styles.legendItem}>
          <span
            className={[
              styles.diffWord,
              styles.diffWrong,
              styles.diffExtra,
            ].join(" ")}
            title="Extra word"
          >
            extra
          </span>
          <span className={styles.legendLabel}>Extra word</span>
        </div>
      </div>
    </div>
