}

function ListenRepeatDiffView({
  alignment,
  showLabels = true,
}: {
  alignment: AlignedWord[];
  showLabels?: boolean;
}) {
  return (
    <div className={styles.sideBySideDiff}>
      {showLabels && (
        <div className={styles.diffColumn}>
          <div
            className={[styles.diffCell, styles.diffRowLabel].join(" ")}
            aria-hidden="true"
          >
            Correct
          </div>
          <div
            className={[styles.diffCell, styles.diffRowLabel].join(" ")}
            aria-hidden="true"
          >
            You
          </div>
        </div>
      )}
      {alignment.map((a, j) => {
        const isMatch = a.type === "match";
        const isDeletion = a.type === "deletion";
        const isInsertion = a.type === "insertion";

        const topClasses = [styles.diffCell];
        const bottomClasses = [styles.diffCell];

        if (isMatch) {
          topClasses.push(styles.diffCorrect);
          bottomClasses.push(styles.diffCorrect);
        } else if (isDeletion) {
          topClasses.push(styles.diffWrong, styles.diffMissing);
          bottomClasses.push(styles.diffPlaceholder);
        } else if (isInsertion) {
          topClasses.push(styles.diffPlaceholder);
          bottomClasses.push(styles.diffWrong, styles.diffExtra);
        } else {
          topClasses.push(styles.diffWrong);
          bottomClasses.push(styles.diffWrong);
        }

        return (
          <div key={j} className={styles.diffColumn}>
            <div
              className={topClasses.join(" ")}
              title={
                a.type === "match"
                  ? "Correct"
                  : a.type === "deletion"
                    ? `Missing: ${a.original}`
                    : a.type === "insertion"
                      ? "(not in original)"
                      : `Expected: ${a.original}`
              }
            >
              {a.original ?? "▪"}
            </div>
            <div
              className={bottomClasses.join(" ")}
              title={
                a.type === "match"
                  ? "Correct"
                  : a.type === "deletion"
                    ? "(not spoken)"
                    : a.type === "insertion"
                      ? `Extra: ${a.recognized}`
                      : `Got: ${a.recognized}`
              }
            >
              {a.recognized ?? "▪"}
            </div>
          </div>
        );
      })}
    </div>
  );
}

export function ListenRepeatPage() {
  const navigate = useNavigate();
  const { questionNumber } = useParams<{ questionNumber: string }>();
  const { data, file, loading, error, loadByQuestionNumber } =
    useQuestion<ProblemData>("toefl/speaking/listen-repeat");
  const { saveScore } = useScoreHistory();
  const {
    display,
    elapsedSeconds,
    running,
    start,
    stop,
    reset: resetTimer,
  } = useElapsedTimer();
  const {
    playing,
    loading: ttsLoading,
    error: ttsError,
    currentTime,
    duration,
    playbackRate,
    setPlaybackRate,
    play,
    pause,
    resume,
    stop: stopTts,
    seek,
  } = useTts();
  const {
    supported: speechSupported,
    transcript,
    error: speechError,
    start: startSpeech,
    stop: stopSpeech,
  } = useSpeechRecognition();
  const transcriptRef = useRef(transcript);

  const [current, setCurrent] = useState(0);
  const [phase, setPhase] = useState<Phase>("playing");
  const [transcripts, setTranscripts] = useState<Record<number, string>>({});
  const [graded, setGraded] = useState(false);
  const [recordingTimeLeft, setRecordingTimeLeft] = useState(0);
  const [processingMessage, setProcessingMessage] = useState<string | null>(
    null,
  );

  const durationRef = useRef(duration);
  const recordingTimerRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const processingTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(
    null,
  );
  useEffect(() => {
    transcriptRef.current = transcript;
  }, [transcript]);

  const parsedQuestionNumber = Number.parseInt(questionNumber ?? "", 10);
  const hasValidQuestionNumber =
    Number.isInteger(parsedQuestionNumber) && parsedQuestionNumber > 0;

  const fileBasename = file ? file.replace(/\.json$/i, "") : "";
  const totalSentences = data?.sentences.length ?? 0;
  const sentence = data?.sentences[current];
  const isLastSentence = current + 1 >= totalSentences;

  useEffect(() => {
    durationRef.current = duration;
  }, [duration]);

  useEffect(() => {
    if (!hasValidQuestionNumber) return;
    loadByQuestionNumber(parsedQuestionNumber);
  }, [hasValidQuestionNumber, loadByQuestionNumber, parsedQuestionNumber]);

  useEffect(() => {
    if (data && !loading && !graded && !running && elapsedSeconds === 0) {
      start();
    }
  }, [data, loading, graded, running, elapsedSeconds, start]);

  const clearRecordingTimer = useCallback(() => {
    if (recordingTimerRef.current) {
      clearInterval(recordingTimerRef.current);
      recordingTimerRef.current = null;
    }
  }, []);

  useEffect(() => {
    if (speechError && phase === "recording") {
      clearRecordingTimer();
    }
  }, [speechError, phase, clearRecordingTimer]);

  const clearProcessingTimeout = useCallback(() => {
    if (processingTimeoutRef.current) {
      clearTimeout(processingTimeoutRef.current);
      processingTimeoutRef.current = null;
    }
  }, []);

  const finishingRef = useRef(false);

  const finishSentence = useCallback(async () => {
    if (finishingRef.current) return;
    finishingRef.current = true;

    clearRecordingTimer();
    clearProcessingTimeout();
    await stopSpeech();
    setPhase("processing");
    setProcessingMessage("Processing your speech...");

    processingTimeoutRef.current = setTimeout(() => {
      setTranscripts((prev) => {
        const next = { ...prev, [current]: transcriptRef.current.trim() };

        if (isLastSentence) {
          const sessionSeconds = stop();
          if (data) {
            const allAlignments = data.sentences.map((s, i) =>
              alignWords(s.text, next[i] ?? ""),
            );
            const correct = allAlignments.reduce(
              (sum, a) => sum + countCorrectWords(a),
              0,
            );
            const total = allAlignments.reduce(
              (sum, a) => sum + countOriginalWords(a),
              0,
            );
            saveScore(
              "toefl/speaking/listen-repeat",
              correct,
              total,
              sessionSeconds,
              file ?? undefined,
            );
          }
          setGraded(true);
          setPhase("review");
          stopTts();
        }

        return next;
      });

      if (!isLastSentence) {
        setPhase("feedback");
      }
      setProcessingMessage(null);
      finishingRef.current = false;
    }, PROCESSING_DELAY_MS);
  }, [
    clearRecordingTimer,
    clearProcessingTimeout,
    stopSpeech,
    current,
    isLastSentence,
    data,
    stop,
    saveScore,
    file,
    stopTts,
  ]);

  const startRecording = useCallback(() => {
    if (!speechSupported) return;
    const audioDuration =
      durationRef.current > 0
        ? durationRef.current
        : (sentence?.wordCount ?? 0) / DEFAULT_WORDS_PER_SECOND;
    const recordingDuration = Math.max(
      3,
      Math.round(audioDuration * RECORDING_MULTIPLIER),
    );

    setRecordingTimeLeft(recordingDuration);
    setPhase("recording");
    startSpeech();

    recordingTimerRef.current = setInterval(() => {
      setRecordingTimeLeft((prev) => {
        if (prev <= 1) {
          void finishSentence();
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
  }, [speechSupported, sentence, startSpeech, finishSentence]);

  const playCurrentSentence = useCallback(() => {
    if (!sentence || !fileBasename) return;
    const url = `/audio/toefl/speaking/listen-repeat/${fileBasename}/${current + 1}.mp3`;
    void play(url, () => {
      setPhase("ready");
    });
  }, [sentence, fileBasename, current, play]);

  const playSentence = useCallback(
    (index: number) => {
      if (!fileBasename) return;
      const url = `/audio/toefl/speaking/listen-repeat/${fileBasename}/${index + 1}.mp3`;
      void play(url);
    },
    [fileBasename, play],
  );

  const handlePlay = useCallback(() => {
    if (playing) {
      pause();
    } else if (currentTime > 0) {
      resume();
    } else {
      playSentence(current);
    }
  }, [playing, currentTime, pause, resume, playSentence, current]);

  const handleStartRecording = useCallback(() => {
    startRecording();
  }, [startRecording]);

  const handleNextQuestion = useCallback(() => {
    if (isLastSentence) return;
    setCurrent((c) => c + 1);
    setPhase("playing");
  }, [isLastSentence]);

  useEffect(() => {
    if (
      data &&
      !loading &&
      !graded &&
      hasValidQuestionNumber &&
      phase === "playing" &&
      !playing &&
      !ttsLoading
    ) {
      playCurrentSentence();
    }
  }, [
    data,
    loading,
    graded,
    hasValidQuestionNumber,
    phase,
    playing,
    ttsLoading,
    playCurrentSentence,
  ]);

  useEffect(() => {
    return () => {
      clearRecordingTimer();
      clearProcessingTimeout();
      void stopSpeech();
      stopTts();
      finishingRef.current = false;
    };
  }, [clearRecordingTimer, clearProcessingTimeout, stopSpeech, stopTts]);

  const handleBackToList = () => {
    clearRecordingTimer();
    clearProcessingTimeout();
    void stopSpeech();
    stopTts();
    resetTimer();
    setCurrent(0);
    setTranscripts({});
    setPhase("playing");
    setGraded(false);
    setRecordingTimeLeft(0);
    setProcessingMessage(null);
    finishingRef.current = false;
    navigate("/toefl/speaking/listen-repeat");
  };

  const handleReplayAudio = () => {
    clearRecordingTimer();
    clearProcessingTimeout();
    void stopSpeech();
    finishingRef.current = false;
    setProcessingMessage(null);
    setPhase("playing");
  };

  const handleRetryRecording = () => {
    clearRecordingTimer();
    clearProcessingTimeout();
    void stopSpeech();
    finishingRef.current = false;
    setProcessingMessage(null);
    setPhase("playing");
  };

  const alignments: AlignedWord[][] = data
    ? data.sentences.map((s, i) => alignWords(s.text, transcripts[i] ?? ""))
    : [];
  const correctWords = alignments.reduce(
    (sum, a) => sum + countCorrectWords(a),
    0,
  );
  const totalWords = alignments.reduce(
    (sum, a) => sum + countOriginalWords(a),
    0,
  );

  return (
    <div>
      {(running || elapsedSeconds > 0) && (
        <FloatingElapsedTimer display={display} running={running} />
      )}
      <SectionHeader
        title="Listen and Repeat"
        subtitle="Listen to the sentence, then repeat it into the microphone."
        backTo="/toefl"
        current={current}
        total={totalSentences}
      />

      <div className={styles.topBar}>
        <Button
          variant="secondary"
          size="sm"
          onClick={handleBackToList}
          disabled={loading}
        >
          Question List
        </Button>
      </div>

      {loading && <LoadingSpinner message="Loading question set..." />}
      {error && (
        <div className={styles.error}>
          <p>{error}</p>
          <p className={styles.errorHint}>
            questions/toefl/speaking/listen-repeat/ Add question JSON under this
            folder.
          </p>
        </div>
      )}
      {!hasValidQuestionNumber && (
        <div className={styles.error}>
          <p>Invalid question number in URL.</p>
        </div>
      )}
      {!speechSupported && !loading && (
        <div className={styles.error}>
          <p>
            Microphone recording is not supported in this browser. Please use
            Chrome, Edge, or Safari.
          </p>
        </div>
      )}
      {speechError && <div className={styles.error}>{speechError}</div>}
      {ttsError && <div className={styles.error}>{ttsError}</div>}

      {data && !loading && hasValidQuestionNumber && !graded && sentence && (
        <div className={styles.card}>
          <p className={styles.qNum}>
            Question {current + 1} / {totalSentences}
          </p>

          {phase === "playing" && (
            <div className={styles.showPhase}>
              <div className={styles.statusIcon}>🔊</div>
              <p className={styles.sentenceDisplay}>Listen carefully...</p>
              <p className={styles.hint}>
                {ttsLoading ? "Loading audio..." : "The sentence is playing."}
              </p>
            </div>
          )}

          {phase === "ready" && (
            <div className={styles.showPhase}>
              <div className={styles.statusIcon}>🎤</div>
              <p className={styles.sentenceDisplay}>Ready to record</p>
              <p className={styles.hint}>
                Click the button below when you are ready to repeat the
                sentence.
              </p>
              <Button onClick={handleStartRecording} variant="accent" size="lg">
                🔴 Start Recording
              </Button>
            </div>
          )}

          {phase === "recording" && (
            <div className={styles.showPhase}>
              <div className={styles.recordingIndicator}>
                <span className={styles.recordingDot} />
                <span className={styles.recordingTimer}>
                  {recordingTimeLeft}s
                </span>
              </div>
              <p className={styles.sentenceDisplay}>Repeat the sentence now</p>
              <p className={styles.hint}>
                Microphone is on. Speak clearly before time runs out.
              </p>
              {transcript && (
                <p className={styles.liveTranscript}>{transcript}</p>
              )}
              {speechError && (
                <Button onClick={handleRetryRecording} variant="accent">
                  🔄 Retry This Sentence
                </Button>
              )}
            </div>
          )}

          {(phase === "processing" || processingMessage) && (
            <div className={styles.showPhase}>
              <LoadingSpinner message={processingMessage ?? "Processing..."} />
            </div>
          )}

          {phase === "feedback" && (
            <div className={styles.feedbackPhase}>
              <div className={styles.playerCard}>
                <div className={styles.playerControls}>
                  <Button
                    onClick={() => seek(Math.max(0, currentTime - 10))}
                    disabled={duration <= 0}
                    size="sm"
                    variant="secondary"
                  >
                    ⏪ 10s
                  </Button>
                  <Button
                    onClick={handlePlay}
                    disabled={ttsLoading}
                    size="md"
                    variant="accent"
                  >
                    {ttsLoading
                      ? "Loading..."
                      : playing
                        ? "⏸ Pause"
                        : currentTime > 0
                          ? "▶ Resume"
                          : "▶ Play Audio"}
                  </Button>
                  <Button
                    onClick={() => seek(Math.min(duration, currentTime + 10))}
                    disabled={duration <= 0}
                    size="sm"
                    variant="secondary"
                  >
                    ⏩ 10s
                  </Button>
                </div>
                <div className={styles.playerControls}>
                  <span className={styles.timeText}>
                    {formatTime(currentTime)} / {formatTime(duration)}
                  </span>
                  <div className={styles.progressBar}>
                    <div
                      className={styles.progressFill}
                      style={{
                        width:
                          duration > 0
                            ? `${(currentTime / duration) * 100}%`
                            : "0%",
                      }}
                    />
                  </div>
                  <span className={styles.timeText} aria-hidden="true" />
                </div>
                <div className={styles.speedControlRow}>
                  <SpeedControl
                    playbackRate={playbackRate}
                    onChange={setPlaybackRate}
                  />
                </div>
                {ttsError && <p className={styles.error}>{ttsError}</p>}
              </div>
              <DiffLegend />
              <p className={styles.fbLabel}>Comparison:</p>
              <ListenRepeatDiffView
                alignment={alignWords(
                  sentence.text,
                  transcripts[current] ?? "",
                )}
              />
              <p className={styles.hint}>
                {countCorrectWords(
                  alignWords(sentence.text, transcripts[current] ?? ""),
                )}
                /
                {countOriginalWords(
                  alignWords(sentence.text, transcripts[current] ?? ""),
                )}{" "}
                words correct
              </p>
              <Button onClick={handleNextQuestion} variant="accent" size="lg">
                Next Question
              </Button>
            </div>
          )}

          {phase !== "feedback" && (
            <div className={styles.playerControls}>
              <Button
                onClick={handleReplayAudio}
                disabled={phase === "playing" || ttsLoading}
                size="sm"
                variant="secondary"
              >
                🔁 Replay Audio
              </Button>
            </div>
          )}
        </div>
      )}

      {graded && data && hasValidQuestionNumber && (
        <>
          <div className={styles.resultCard}>
            <h2>Section Complete</h2>
            <p className={styles.hint}>Review your answers below.</p>
            <DiffLegend />
            <div className={styles.scoreBox}>
              <span className={styles.scoreNum}>{correctWords}</span>
              <span className={styles.scoreDen}>/{totalWords}</span>
              <span className={styles.scorePct}>
                (
                {totalWords > 0
                  ? Math.round((correctWords / totalWords) * 100)
                  : 0}
                %)
              </span>
            </div>
            <ProgressBar
              current={correctWords}
              total={totalWords}
              label="Words Correct"
            />
            <BackButton onClick={handleBackToList} size="lg" />
          </div>

          {data.sentences.map((s, i) => {
            const alignment = alignWords(s.text, transcripts[i] ?? "");
            const correct = countCorrectWords(alignment);
            const total = countOriginalWords(alignment);
            return (
              <div key={s.id} className={styles.card}>
                <p className={styles.qNum}>
                  Question {i + 1} — {correct}/{total} words
                </p>
                <div className={styles.feedbackPhase}>
                  <Button
                    onClick={() => playSentence(i)}
                    disabled={ttsLoading}
                    size="sm"
                    variant="secondary"
                  >
                    ▶ Play Audio
                  </Button>
                  <p className={styles.fbLabel}>Comparison:</p>
                  <ListenRepeatDiffView alignment={alignment} />
                </div>
              </div>
            );
          })}
        </>
      )}
    </div>
  );
}

import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { SectionHeader } from "../../../components/layout/SectionHeader";
import { BackButton } from "../../../components/ui/BackButton";
import { Button } from "../../../components/ui/Button";
import { GradingRequestPanel } from "../../../components/ui/GradingRequestPanel";
import { LoadingSpinner } from "../../../components/ui/LoadingSpinner";
import { Timer } from "../../../components/ui/Timer";
import { ProgressBar } from "../../../components/ui/ProgressBar";
import { useTimer } from "../../../hooks/useTimer";
import { useQuestion } from "../../../hooks/useQuestion";
import {
  buildGradingMessage,
  buildProblemId,
  clearDraft,
  copyText,
  loadDraft,
  saveAnswerSubmission,
  saveDraft,
} from "../../../lib/answerSubmission";
import styles from "./TakeInterviewPage.module.css";

interface InterviewQuestion {
  id: string;
  type: string;
  question: string;
  modelAnswer: string;
  evaluationPoints: string[];
}

interface ProblemData {
  questions: InterviewQuestion[];
}

const TYPE_LABELS: Record<string, string> = {
  personal: "Personal Experience",
  opinion: "Opinion",
  hypothetical: "Hypothetical Situation",
  comparison: "Comparison / Choice",
};
const TASK_ID = "toefl/speaking/interview";

export function TakeInterviewPage() {
  const navigate = useNavigate();
  const { questionNumber } = useParams<{ questionNumber: string }>();
  const { data, file, loading, error, loadByQuestionNumber } =
    useQuestion<ProblemData>(TASK_ID);
  const [current, setCurrent] = useState(0);
  const [userText, setUserText] = useState("");
  const [phase, setPhase] = useState<"pre" | "answering" | "submitted">("pre");
  const [showModel, setShowModel] = useState(false);
  const [done, setDone] = useState(false);
  const [savingAnswer, setSavingAnswer] = useState(false);
  const [saveError, setSaveError] = useState<string | null>(null);
  const [answerId, setAnswerId] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  const q = data?.questions[current];
  const problemId =
    file && q
      ? buildProblemId(TASK_ID, file, q.id || String(current + 1))
      : null;
  const gradingMessage =
    problemId && answerId ? buildGradingMessage(problemId, answerId) : null;

  const submitAnswer = async () => {
    setPhase("submitted");
    if (!q || !problemId || answerId || savingAnswer) return;
    setSavingAnswer(true);
    setSaveError(null);
    try {
      const result = await saveAnswerSubmission({
        taskId: TASK_ID,
        problemId,
        response: userText,
        question: q,
      });
      clearDraft(problemId);
      setAnswerId(result.answerId);
    } catch (e) {
      setSaveError(
        e instanceof Error ? e.message : "Failed to save your answer.",
      );
    } finally {
      setSavingAnswer(false);
    }
  };

  const timer = useTimer(45, () => {
    void submitAnswer();
  });

  const parsedQuestionNumber = Number.parseInt(questionNumber ?? "", 10);
  const hasValidQuestionNumber =
    Number.isInteger(parsedQuestionNumber) && parsedQuestionNumber > 0;

  useEffect(() => {
    if (!hasValidQuestionNumber) return;
    loadByQuestionNumber(parsedQuestionNumber);
  }, [hasValidQuestionNumber, loadByQuestionNumber, parsedQuestionNumber]);

  useEffect(() => {
    if (!problemId) return;
    setUserText(loadDraft(problemId));
    setSaveError(null);
    setAnswerId(null);
    setCopied(false);
  }, [problemId]);

  useEffect(() => {
    if (!problemId || phase === "submitted") return;
    saveDraft(problemId, userText);
  }, [problemId, phase, userText]);

  const handleStart = () => {
    setPhase("answering");
    timer.start();
  };
  const handleSubmit = () => {
    timer.stop();
    void submitAnswer();
  };
  const handleCopy = async () => {
    if (!gradingMessage) return;
    try {
      const ok = await copyText(gradingMessage);
      if (!ok) {
        setSaveError("Clipboard is not available in this environment.");
        return;
      }
      setCopied(true);
    } catch {
      setSaveError("Failed to copy.");
    }
  };

  const handleNext = () => {
    if (!data) return;
    if (current + 1 >= data.questions.length) {
      setDone(true);
      return;
    }
    setCurrent((c) => c + 1);
    setUserText("");
    setPhase("pre");
    setShowModel(false);
    setSavingAnswer(false);
    setSaveError(null);
    setAnswerId(null);
    setCopied(false);
    timer.reset();
  };

  const handleBackToList = () => {
    setCurrent(0);
    setUserText("");
    setPhase("pre");
    setShowModel(false);
    setDone(false);
    setSavingAnswer(false);
    setSaveError(null);
    setAnswerId(null);
    setCopied(false);
    timer.reset();
    navigate("/toefl/speaking/interview");
  };

  return (
    <div>
      <SectionHeader
        title="Take an Interview"
        subtitle="Answer interview prompts (no prep time, 45 seconds each)."
        backTo="/toefl"
        current={done ? data?.questions.length : current}
        total={data?.questions.length}
      />

      <div className={styles.topBar}>
        <Button
          variant="secondary"
          size="sm"
          onClick={handleBackToList}
          disabled={loading || phase === "answering"}
        >
          Question List
        </Button>
      </div>

      {loading && <LoadingSpinner message="Loading question set..." />}
      {error && (
        <div className={styles.error}>
          <p>{error}</p>
          <p className={styles.errorHint}>
            Add question JSON under questions/toefl/speaking/interview/.
          </p>
        </div>
      )}
      {!hasValidQuestionNumber && (
        <div className={styles.error}>
          <p>Invalid question number in URL.</p>
        </div>
      )}

      {data && !loading && hasValidQuestionNumber && !done && q && (
        <div className={styles.card}>
          <div className={styles.cardHeader}>
            <span className={styles.typeTag}>
              {TYPE_LABELS[q.type] ?? q.type}
            </span>
            <span className={styles.qNum}>
              Question {current + 1} / {data.questions.length}
            </span>
          </div>
          <p className={styles.question}>{q.question}</p>

          {phase === "pre" && (
            <div className={styles.preBox}>
              <p className={styles.preNote}>
                There is no prep time. Press Start to begin the 45-second timer.
              </p>
              <Button size="lg" onClick={handleStart}>
                Start
              </Button>
            </div>
          )}

          {(phase === "answering" || phase === "submitted") && (
            <div className={styles.answerArea}>
              <Timer
                display={timer.display}
                isWarning={timer.isWarning}
                isExpired={timer.isExpired}
              />
              <textarea
                className={styles.textarea}
                value={userText}
                onChange={(e) => setUserText(e.target.value)}
                placeholder="Type your response here (spoken in the real test)..."
                disabled={phase === "submitted"}
                rows={8}
              />
              {phase === "answering" && (
                <Button onClick={handleSubmit}>Submit</Button>
              )}
            </div>
          )}

          {phase === "submitted" && (
            <div className={styles.feedbackArea}>
              <GradingRequestPanel
                saving={savingAnswer}
                error={saveError}
                message={gradingMessage}
                copied={copied}
                onCopy={() => {
                  void handleCopy();
                }}
              />
              <div className={styles.evalCard}>
                <h3>Evaluation Points</h3>
                <ul>
                  {q.evaluationPoints.map((pt, i) => (
                    <li key={i}>{pt}</li>
                  ))}
                </ul>
              </div>
              <div className={styles.modelArea}>
                <Button
                  variant="secondary"
                  onClick={() => setShowModel((v) => !v)}
                >
                  {showModel ? "Hide Model Answer" : "Show Model Answer"}
                </Button>
                {showModel && (
                  <div className={styles.modelAnswer}>
                    <h3>Model Answer</h3>
                    <p>{q.modelAnswer}</p>
                  </div>
                )}
              </div>
              <Button onClick={handleNext}>
                {current + 1 < data.questions.length
                  ? "Next Question"
                  : "Finish"}
              </Button>
            </div>
          )}
        </div>
      )}

      {done && data && hasValidQuestionNumber && (
        <div className={styles.resultCard}>
          <h2>Interview Complete</h2>
          <p>You answered all {data.questions.length} questions.</p>
          <ProgressBar
            current={data.questions.length}
            total={data.questions.length}
            label="Complete"
          />
          <BackButton onClick={handleBackToList} size="lg" />
        </div>
      )}
    </div>
  );
}

