import { useState, useEffect, useRef } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { SectionHeader } from "../../../components/layout/SectionHeader";
import { Button } from "../../../components/ui/Button";
import { LoadingSpinner } from "../../../components/ui/LoadingSpinner";
import { ProgressBar } from "../../../components/ui/ProgressBar";
import { FloatingElapsedTimer } from "../../../components/ui/FloatingElapsedTimer";
import { useElapsedTimer } from "../../../hooks/useElapsedTimer";
import { useQuestion } from "../../../hooks/useQuestion";
import { useScoreHistory } from "../../../hooks/useScoreHistory";
import { useTts } from "../../../hooks/useTts";
import styles from "./ListenResponsePage.module.css";

interface ResponseQuestion {
  id: string;
  context: string;
  stem: string;
  options: { A: string; B: string; C: string };
  correct: string;
  explanation: string;
}

interface ProblemData {
  title: string;
  questions: ResponseQuestion[];
  audioSegments: { role: string; text: string }[];
}

const TASK_ID = "toefl/listening/response";

export function ListenResponsePage() {
  const navigate = useNavigate();
  const { questionNumber } = useParams<{ questionNumber: string }>();
  const { data, file, loading, error, loadByQuestionNumber } =
    useQuestion<ProblemData>(TASK_ID);
  const { saveScore } = useScoreHistory();
  const {
    display,
    elapsedSeconds,
    running,
    start,
    stop,
    reset: resetTimer,
  } = useElapsedTimer();
  const { loading: ttsLoading, playSegmentsWithGaps } = useTts();
  const fileBasename = file ? file.replace(/\.json$/i, "") : "";

  const [currentIndex, setCurrentIndex] = useState(0);
  const [selected, setSelected] = useState<Record<string, string>>({});
  const [graded, setGraded] = useState(false);
  const audioStartedRef = useRef<Set<number>>(new Set());

  const parsedQuestionNumber = Number.parseInt(questionNumber ?? "", 10);
  const hasValidQuestionNumber =
    Number.isInteger(parsedQuestionNumber) && parsedQuestionNumber > 0;

  useEffect(() => {
    if (!hasValidQuestionNumber) return;
    loadByQuestionNumber(parsedQuestionNumber);
  }, [hasValidQuestionNumber, loadByQuestionNumber, parsedQuestionNumber]);

  useEffect(() => {
    if (data && !loading && !graded && !running && elapsedSeconds === 0) {
      start();
    }
  }, [data, loading, graded, running, elapsedSeconds, start]);

  const questions = data?.questions ?? [];

  useEffect(() => {
    if (data && !graded && !audioStartedRef.current.has(currentIndex)) {
      const url = `/audio/${TASK_ID}/${fileBasename}/${currentIndex + 1}.mp3`;
      audioStartedRef.current = new Set(audioStartedRef.current).add(
        currentIndex,
      );
      playSegmentsWithGaps([url], []);
    }
  }, [data, currentIndex, graded, playSegmentsWithGaps, fileBasename]);

  const currentQuestion = questions[currentIndex];
  const totalQuestions = questions.length;
  const allAnswered = questions.every((q) => selected[q.id]);
  const totalCorrect = questions.filter(
    (q) => selected[q.id] === q.correct,
  ).length;

  const handleSelect = (opt: string) => {
    if (!currentQuestion || graded) return;
    setSelected((s) => ({ ...s, [currentQuestion.id]: opt }));
  };

  const handleNext = () => {
    if (currentIndex < totalQuestions - 1) {
      setCurrentIndex((i) => i + 1);
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      setCurrentIndex((i) => i - 1);
    }
  };

  const retake = () => {
    if (!graded) return;
    setSelected({});
    setCurrentIndex(0);
    setGraded(false);
    audioStartedRef.current = new Set();
    resetTimer();
  };

  const handleSubmit = () => {
    const sessionSeconds = stop();
    if (data) {
      const correct = data.questions.filter(
        (q) => selected[q.id] === q.correct,
      ).length;
      saveScore(
        TASK_ID,
        correct,
        data.questions.length,
        sessionSeconds,
        file ?? undefined,
      );
    }
    setGraded(true);
  };

  const handleReplayAudio = () => {
    if (!data || graded) return;
    const url = `/audio/${TASK_ID}/${fileBasename}/${currentIndex + 1}.mp3`;
    playSegmentsWithGaps([url], []);
  };

  const handleBackToList = () => {
    resetTimer();
    setCurrentIndex(0);
    setSelected({});
    setGraded(false);
    audioStartedRef.current = new Set();
    navigate("/toefl/listening/response");
  };

  return (
    <div>
      {(running || elapsedSeconds > 0) && (
        <FloatingElapsedTimer display={display} running={running} />
      )}
      <SectionHeader
        title="Listen and Choose a Response"
        subtitle="Listen to each utterance and choose the best response."
        backTo="/toefl"
        current={Object.keys(selected).length}
        total={totalQuestions}
      />

      <div className={styles.topBar}>
        <Button
          variant="secondary"
          size="sm"
          onClick={handleBackToList}
          disabled={loading}
        >
          Question List
        </Button>
      </div>

      {loading && <LoadingSpinner message="Loading question set..." />}
      {error && (
        <div className={styles.error}>
          <p>{error}</p>
          <p className={styles.errorHint}>
            Add question JSON under questions/{TASK_ID}/.
          </p>
        </div>
      )}
      {!hasValidQuestionNumber && (
        <div className={styles.error}>
          <p>Invalid question number in URL.</p>
        </div>
      )}

      {data && !loading && hasValidQuestionNumber && (
        <>
          {graded && (
            <>
              <div className={styles.resultCard}>
                <h2>Section Complete</h2>
                <div className={styles.scoreBox}>
                  <span className={styles.scoreNum}>{totalCorrect}</span>
                  <span className={styles.scoreDen}>/{totalQuestions}</span>
                  <span className={styles.scorePct}>
                    ({Math.round((totalCorrect / totalQuestions) * 100)}%)
                  </span>
                </div>
                <ProgressBar
                  current={totalCorrect}
                  total={totalQuestions}
                  label="Accuracy"
                />
                <div className={styles.resultActions}>
                  <Button onClick={retake} size="md" variant="secondary">
                    Retake
                  </Button>
                </div>
              </div>

              {questions.map((q, qIndex) => {
                const sel = selected[q.id];
                const isCorrect = sel === q.correct;
                return (
                  <div key={q.id} className={styles.reviewCard}>
                    <div className={styles.reviewHeader}>
                      <strong>Question {qIndex + 1}</strong>
                      <span
                        className={
                          isCorrect
                            ? styles.reviewCorrect
                            : styles.reviewIncorrect
                        }
                      >
                        {isCorrect ? "Correct" : "Incorrect"}
                      </span>
                    </div>
                    <span className={styles.reviewContext}>{q.context}</span>
                    <p className={styles.reviewStem}>{q.stem}</p>
                    <div className={styles.reviewOptions}>
                      {(["A", "B", "C"] as const).map((opt) => {
                        let cls = styles.reviewOpt;
                        if (opt === q.correct)
                          cls += " " + styles.reviewOptCorrect;
                        if (sel === opt && opt !== q.correct)
                          cls += " " + styles.reviewOptWrong;
                        return (
                          <div key={opt} className={cls}>
                            <span className={styles.optLabel}>{opt}</span>
                            <span>{q.options[opt]}</span>
                          </div>
                        );
                      })}
                    </div>
                    <p className={styles.explanation}>{q.explanation}</p>
                  </div>
                );
              })}
            </>
          )}

          {!graded && currentQuestion && (
            <div className={styles.questionCard}>
              <div className={styles.qProgress}>
                Question {currentIndex + 1} of {totalQuestions}
              </div>

              <span className={styles.contextBadge}>
                {currentQuestion.context}
              </span>

              <div className={styles.audioArea}>
                {ttsLoading && (
                  <p className={styles.loadingAudio}>Loading audio...</p>
                )}
                {!ttsLoading && (
                  <Button
                    onClick={handleReplayAudio}
                    size="sm"
                    variant="secondary"
                  >
                    Play Audio
                  </Button>
                )}
              </div>

              <div className={styles.options}>
                {(["A", "B", "C"] as const).map((opt) => {
                  const sel = selected[currentQuestion.id];
                  return (
                    <button
                      key={opt}
                      className={`${styles.option} ${
                        sel === opt ? styles.selected : ""
                      }`}
                      onClick={() => handleSelect(opt)}
                    >
                      <span className={styles.optLabel}>{opt}</span>
                      <span>{currentQuestion.options[opt]}</span>
                    </button>
                  );
                })}
              </div>

              <div className={styles.navButtons}>
                <Button
                  variant="secondary"
                  onClick={handlePrev}
                  disabled={currentIndex === 0}
                  size="sm"
                >
                  Previous
                </Button>
                <span className={styles.qStatus}>
                  {selected[currentQuestion.id]
                    ? "Answered"
                    : "Select a response"}
                </span>
                {currentIndex < totalQuestions - 1 ? (
                  <Button
                    onClick={handleNext}
                    disabled={!selected[currentQuestion.id]}
                    size="sm"
                  >
                    Next
                  </Button>
                ) : (
                  <Button
                    onClick={handleSubmit}
                    disabled={!allAnswered}
                    size="sm"
                  >
                    Submit
                  </Button>
                )}
              </div>
            </div>
          )}
        </>
      )}
    </div>
  );
}

import { useState, useEffect, useRef, useCallback } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { SectionHeader } from "../layout/SectionHeader";
import { Button } from "../ui/Button";
import { LoadingSpinner } from "../ui/LoadingSpinner";
import { ProgressBar } from "../ui/ProgressBar";
import { FloatingElapsedTimer } from "../ui/FloatingElapsedTimer";
import { SpeedControl } from "../ui/SpeedControl";
import { useElapsedTimer } from "../../hooks/useElapsedTimer";
import { useQuestion } from "../../hooks/useQuestion";
import { useScoreHistory, type TaskId } from "../../hooks/useScoreHistory";
import { useTts } from "../../hooks/useTts";
import styles from "./ListeningTaskBase.module.css";

interface ListeningQuestion {
  id: string;
  stem: string;
  options: string[];
  correctIndex: number;
  type: string;
  explanation: string;
}

interface ProblemData {
  title: string;
  audioSegments: { role: string; text: string }[];
  transcript: string;
  questions: ListeningQuestion[];
}

function formatTime(seconds: number) {
  const m = Math.floor(seconds / 60);
  const s = Math.floor(seconds % 60);
  return `${m}:${String(s).padStart(2, "0")}`;
}

interface ListeningTaskBaseProps {
  taskId: TaskId;
  title: string;
  subtitle: string;
  backTo: string;
  readQuestionsAloud?: boolean;
  showSpeedControl?: boolean;
}

export function ListeningTaskBase({
  taskId,
  title,
  subtitle,
  backTo,
  readQuestionsAloud,
  showSpeedControl,
}: ListeningTaskBaseProps) {
  const navigate = useNavigate();
  const { questionNumber } = useParams<{ questionNumber: string }>();
  const { data, file, loading, error, loadByQuestionNumber } =
    useQuestion<ProblemData>(taskId);
  const { saveScore } = useScoreHistory();
  const {
    display,
    elapsedSeconds,
    running,
    start,
    stop,
    reset: resetTimer,
  } = useElapsedTimer();
  const {
    playing,
    loading: ttsLoading,
    error: ttsError,
    currentTime,
    duration,
    playbackRate,
    setPlaybackRate,
    playSegments,
    playSegmentsWithGaps,
    pause,
    resume,
    stop: stopTts,
    seek,
  } = useTts();
  const fileBasename = file ? file.replace(/\.json$/i, "") : "";

  const [selections, setSelections] = useState<Record<number, number>>({});
  const [graded, setGraded] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const progressBarRef = useRef<HTMLDivElement>(null);

  const parsedQuestionNumber = Number.parseInt(questionNumber ?? "", 10);
  const hasValidQuestionNumber =
    Number.isInteger(parsedQuestionNumber) && parsedQuestionNumber > 0;

  useEffect(() => {
    if (!hasValidQuestionNumber) return;
    loadByQuestionNumber(parsedQuestionNumber);
  }, [hasValidQuestionNumber, loadByQuestionNumber, parsedQuestionNumber]);

  useEffect(() => {
    if (data && !loading && !graded && !running && elapsedSeconds === 0) {
      start();
    }
  }, [data, loading, graded, running, elapsedSeconds, start]);

  const handleSelect = (qIndex: number, optionIndex: number) => {
    if (graded) return;
    setSelections((s) => ({ ...s, [qIndex]: optionIndex }));
  };

  const getSeekTime = useCallback(
    (clientX: number) => {
      if (!progressBarRef.current || duration <= 0) return null;
      const rect = progressBarRef.current.getBoundingClientRect();
      const ratio = (clientX - rect.left) / rect.width;
      return Math.max(0, Math.min(ratio * duration, duration));
    },
    [duration],
  );

  const handleBarMouseDown = useCallback(
    (e: React.MouseEvent<HTMLDivElement>) => {
      if (!graded || duration <= 0) return;
      const time = getSeekTime(e.clientX);
      if (time !== null) seek(time);
      setIsDragging(true);
    },
    [graded, duration, getSeekTime, seek],
  );

  useEffect(() => {
    if (!isDragging) return;
    const onMove = (e: MouseEvent) => {
      const time = getSeekTime(e.clientX);
      if (time !== null) seek(time);
    };
    const onUp = () => setIsDragging(false);
    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseup", onUp);
    return () => {
      window.removeEventListener("mousemove", onMove);
      window.removeEventListener("mouseup", onUp);
    };
  }, [isDragging, getSeekTime, seek]);

  const correctCount = data
    ? data.questions.filter(
        (_, i) => selections[i] === data.questions[i].correctIndex,
      ).length
    : 0;
  const totalQuestions = data?.questions.length ?? 0;

  const handleSubmit = () => {
    const sessionSeconds = stop();
    if (data) {
      saveScore(
        taskId,
        correctCount,
        totalQuestions,
        sessionSeconds,
        file ?? undefined,
      );
    }
    setGraded(true);
    stopTts();
  };

  const handleBackToList = () => {
    resetTimer();
    setSelections({});
    setGraded(false);
    stopTts();
    navigate(`/${taskId}`);
  };

  const allAnswered =
    totalQuestions > 0 && Object.keys(selections).length === totalQuestions;

  const handlePlay = () => {
    if (playing) {
      pause();
    } else if (currentTime > 0) {
      resume();
    } else {
      const urls = data!.audioSegments.map(
        (_, i) => `/audio/${taskId}/${fileBasename}/${i + 1}.mp3`,
      );
      if (readQuestionsAloud) {
        const convCount = data!.audioSegments.length - data!.questions.length;
        const gaps: number[] = [];
        for (let i = 0; i < data!.audioSegments.length - 1; i++) {
          if (i < convCount - 1) gaps.push(0);
          else if (i === convCount - 1) gaps.push(3);
          else gaps.push(5);
        }
        void playSegmentsWithGaps(urls, gaps);
      } else {
        void playSegments(urls);
      }
    }
  };

  return (
    <div>
      {(running || elapsedSeconds > 0) && (
        <FloatingElapsedTimer display={display} running={running} />
      )}
      <SectionHeader
        title={title}
        subtitle={subtitle}
        backTo={backTo}
        current={Object.keys(selections).length}
        total={totalQuestions}
      />

      <div className={styles.topBar}>
        <Button
          variant="secondary"
          size="sm"
          onClick={handleBackToList}
          disabled={loading}
        >
          Question List
        </Button>
      </div>

      {loading && <LoadingSpinner message="Loading question set..." />}
      {error && (
        <div className={styles.errorText}>
          <p>{error}</p>
          <p>questions/{taskId}/</p>
        </div>
      )}
      {!hasValidQuestionNumber && (
        <div className={styles.errorText}>
          <p>Invalid question number in URL.</p>
        </div>
      )}

      {data && !loading && hasValidQuestionNumber && (
        <>
          <div className={styles.playerCard}>
            <h3>{data.title}</h3>
            <div className={styles.playerControls}>
              <Button
                onClick={() => seek(Math.max(0, currentTime - 10))}
                disabled={duration <= 0}
                size="sm"
                variant="secondary"
              >
                ⏪ 10s
              </Button>
              <Button onClick={handlePlay} disabled={ttsLoading} size="md">
                {ttsLoading
                  ? "Loading..."
                  : playing
                    ? "⏸ Pause"
                    : currentTime > 0
                      ? "▶ Resume"
                      : "▶ Play Audio"}
              </Button>
              <Button
                onClick={() => seek(Math.min(duration, currentTime + 10))}
                disabled={duration <= 0}
                size="sm"
                variant="secondary"
              >
                ⏩ 10s
              </Button>
            </div>
            {(playing || currentTime > 0) && (
              <div className={styles.playerControls}>
                <span className={styles.timeText}>
                  {formatTime(currentTime)} / {formatTime(duration)}
                </span>
                <div
                  ref={progressBarRef}
                  className={`${styles.progressBar} ${graded ? styles.progressBarSeekable : ""}`}
                  onMouseDown={handleBarMouseDown}
                >
                  <div
                    className={styles.progressFill}
                    style={{
                      width:
                        duration > 0
                          ? `${(currentTime / duration) * 100}%`
                          : "0%",
                    }}
                  />
                </div>
                <span className={styles.timeText} aria-hidden="true" />
              </div>
            )}
            {showSpeedControl && duration > 0 && (
              <div className={styles.speedControlRow}>
                <SpeedControl
                  playbackRate={playbackRate}
                  onChange={setPlaybackRate}
                />
              </div>
            )}
            {ttsError && <p className={styles.errorText}>{ttsError}</p>}
          </div>

          {!graded && (
            <div className={styles.submitArea}>
              <Button onClick={handleSubmit} disabled={!allAnswered} size="lg">
                Submit Answers
              </Button>
            </div>
          )}

          {graded && (
            <div className={styles.resultCard}>
              <h2>Section Complete</h2>
              <div className={styles.scoreBox}>
                <span className={styles.scoreNum}>{correctCount}</span>
                <span className={styles.scoreDen}>/{totalQuestions}</span>
                <span className={styles.scorePct}>
                  ({Math.round((correctCount / totalQuestions) * 100)}%)
                </span>
              </div>
              <ProgressBar
                current={correctCount}
                total={totalQuestions}
                label="Correct"
              />
              <div className={styles.transcript}>
                <strong>Transcript</strong>
                {data.audioSegments
                  .filter((seg) => seg.role !== "Narrator")
                  .map((seg, i) => (
                    <p key={i}>
                      {seg.role}: {seg.text}
                    </p>
                  ))}
              </div>
            </div>
          )}

          {data.questions.map((q, qIndex) => {
            const selected = selections[qIndex];
            const isCorrect = selected === q.correctIndex;
            return (
              <div key={q.id} className={styles.questionCard}>
                <p>
                  <strong>
                    Question {qIndex + 1} / {totalQuestions}
                  </strong>
                  {graded && (
                    <span style={{ marginLeft: 8 }}>
                      {isCorrect ? "✓ Correct" : "✗ Incorrect"}
                    </span>
                  )}
                </p>
                <p>{q.stem}</p>
                <div className={styles.options}>
                  {q.options.map((opt, optIndex) => {
                    let optionClass = styles.option;
                    if (!graded && selected === optIndex) {
                      optionClass += " " + styles.optionSelected;
                    }
                    if (graded && optIndex === q.correctIndex) {
                      optionClass += " " + styles.optionCorrect;
                    }
                    if (
                      graded &&
                      selected === optIndex &&
                      optIndex !== q.correctIndex
                    ) {
                      optionClass += " " + styles.optionIncorrect;
                    }
                    return (
                      <button
                        key={optIndex}
                        type="button"
                        className={optionClass}
                        onClick={() => handleSelect(qIndex, optIndex)}
                      >
                        <span className={styles.optionIndex}>
                          {String.fromCharCode(65 + optIndex)}.
                        </span>
                        <span>{opt}</span>
                      </button>
                    );
                  })}
                </div>
                {graded && (
                  <div className={styles.explanation}>{q.explanation}</div>
                )}
              </div>
            );
          })}
        </>
      )}
    </div>
  );
}

import { useState, useEffect, useCallback } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { SectionHeader } from "../components/layout/SectionHeader";
import { Button } from "../components/ui/Button";
import { LoadingSpinner } from "../components/ui/LoadingSpinner";
import { useTts } from "../hooks/useTts";
import { useQuestion } from "../hooks/useQuestion";
import { SpeedControl } from "../components/ui/SpeedControl";
import styles from "./ShadowingPage.module.css";

interface Sentence {
  id: string;
  text: string;
  wordCount: number;
}

interface ProblemData {
  title: string;
  sentences: Sentence[];
}

function formatTime(seconds: number) {
  const m = Math.floor(seconds / 60);
  const s = Math.floor(seconds % 60);
  return `${m}:${String(s).padStart(2, "0")}`;
}

function ShadowingContent({ data, file }: { data: ProblemData; file: string }) {
  const {
    playing,
    loading: ttsLoading,
    error: ttsError,
    currentTime,
    duration,
    playbackRate,
    setPlaybackRate,
    play,
    pause,
    resume,
    stop,
  } = useTts();
  const [current, setCurrent] = useState(0);
  const [showText, setShowText] = useState(false);
  const fileBasename = file.replace(/\.json$/i, "");

  useEffect(() => {
    return () => stop();
  }, [stop]);

  const handlePlay = useCallback(() => {
    const sentence = data.sentences[current];
    if (!sentence) return;
    if (playing) {
      pause();
    } else if (currentTime > 0) {
      resume();
    } else {
      play(`/audio/shadowing/${fileBasename}/${current + 1}.mp3`);
    }
  }, [data, current, playing, currentTime, play, pause, resume, fileBasename]);

  const totalSentences = data.sentences.length;
  const safeCurrent = current >= totalSentences ? 0 : current;
  const sentence = data.sentences[safeCurrent];

  const handlePrev = () => {
    if (safeCurrent <= 0) return;
    stop();
    setCurrent((c) => c - 1);
    setShowText(false);
  };

  const handleNext = () => {
    if (safeCurrent + 1 >= totalSentences) return;
    stop();
    setCurrent((c) => c + 1);
    setShowText(false);
  };

  return (
    <>
      <div className={styles.progressRow}>
        <span className={styles.progressText}>
          {safeCurrent + 1} / {totalSentences}
        </span>
      </div>

      <div className={styles.card}>
        <div className={styles.playerSection}>
          <Button
            onClick={handlePlay}
            disabled={ttsLoading || !sentence}
            size="lg"
            variant="accent"
          >
            {ttsLoading
              ? "Loading..."
              : playing
                ? "Pause"
                : currentTime > 0
                  ? "Resume"
                  : "Play"}
          </Button>
          <SpeedControl
            playbackRate={playbackRate}
            onChange={setPlaybackRate}
            showSlider
          />
          {duration > 0 && (
            <span className={styles.timeText}>
              {formatTime(currentTime)} / {formatTime(duration)}
            </span>
          )}
          {ttsError && <p className={styles.error}>{ttsError}</p>}
        </div>

        <div className={styles.textSection}>
          {sentence && (
            <>
              <div className={styles.sentenceArea}>
                {showText ? (
                  <p className={styles.sentenceText}>{sentence.text}</p>
                ) : (
                  <p className={styles.hiddenText}>
                    {"\u00B7 ".repeat(sentence.text.split(/\s+/).length)}
                  </p>
                )}
              </div>
              <Button
                variant="secondary"
                size="sm"
                onClick={() => setShowText((s) => !s)}
              >
                {showText ? "Hide Text" : "Show Text"}
              </Button>
            </>
          )}
        </div>

        <div className={styles.navSection}>
          <Button
            variant="secondary"
            onClick={handlePrev}
            disabled={safeCurrent <= 0}
          >
            Previous
          </Button>
          <Button
            variant="secondary"
            onClick={handleNext}
            disabled={safeCurrent + 1 >= totalSentences}
          >
            Next
          </Button>
        </div>
      </div>
    </>
  );
}

export function ShadowingPage() {
  const navigate = useNavigate();
  const { questionNumber } = useParams<{ questionNumber: string }>();
  const { data, file, loading, error, loadByQuestionNumber } =
    useQuestion<ProblemData>("shadowing");

  const parsedQuestionNumber = Number.parseInt(questionNumber ?? "", 10);
  const hasValidQuestionNumber =
    Number.isInteger(parsedQuestionNumber) && parsedQuestionNumber > 0;

  useEffect(() => {
    if (!hasValidQuestionNumber) return;
    loadByQuestionNumber(parsedQuestionNumber);
  }, [hasValidQuestionNumber, loadByQuestionNumber, parsedQuestionNumber]);

  const handleBackToList = () => {
    navigate("/shadowing");
  };

  return (
    <div>
      <SectionHeader
        title="Shadowing Practice"
        subtitle={data?.title ?? "Listen and repeat to improve pronunciation."}
        backTo="/"
        current={0}
        total={0}
      />

      <div className={styles.topBar}>
        <Button
          variant="secondary"
          size="sm"
          onClick={handleBackToList}
          disabled={loading}
        >
          Question List
        </Button>
      </div>

      {loading && <LoadingSpinner message="Loading shadowing set..." />}
      {error && (
        <div className={styles.error}>
          <p>{error}</p>
          <p className={styles.errorHint}>
            Add question JSON under public/questions/shadowing/
          </p>
        </div>
      )}
      {!hasValidQuestionNumber && (
        <div className={styles.error}>
          <p>Invalid question number in URL.</p>
        </div>
      )}

      {data && !loading && hasValidQuestionNumber && (
        <ShadowingContent
          key={parsedQuestionNumber}
          data={data}
          file={file ?? ""}
        />
      )}
    </div>
  );
}

