export function normalizeWord(word: string): string {
  const normalized = word.toLowerCase().replace(/[^a-z0-9']/g, "");
  return NUMBER_WORDS[normalized] ?? normalized;
}

export interface AlignedWord {
  type: "match" | "substitution" | "deletion" | "insertion";
  original: string | null;
  recognized: string | null;
  correct: boolean;
}

export function alignWords(
  original: string,
  recognized: string,
): AlignedWord[] {
  const origWords = original.trim().split(/\s+/).filter(Boolean);
  const recWords = recognized.trim().split(/\s+/).filter(Boolean);

  const m = origWords.length;
  const n = recWords.length;

  const dp: number[][] = Array.from({ length: m + 1 }, () =>
    Array.from({ length: n + 1 }, () => 0),
  );

  for (let i = 0; i <= m; i++) dp[i][0] = i;
  for (let j = 0; j <= n; j++) dp[0][j] = j;

  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      const cost =
        normalizeWord(origWords[i - 1]) === normalizeWord(recWords[j - 1])
          ? 0
          : 1;
      dp[i][j] = Math.min(
        dp[i - 1][j] + 1,
        dp[i][j - 1] + 1,
        dp[i - 1][j - 1] + cost,
      );
    }
  }

  const alignment: AlignedWord[] = [];
  let i = m;
  let j = n;

  while (i > 0 || j > 0) {
    if (i > 0 && j > 0) {
      const cost =
        normalizeWord(origWords[i - 1]) === normalizeWord(recWords[j - 1])
          ? 0
          : 1;
      if (dp[i][j] === dp[i - 1][j - 1] + cost) {
        const matched = cost === 0;
        alignment.unshift({
          type: matched ? "match" : "substitution",
          original: origWords[i - 1],
          recognized: recWords[j - 1],
          correct: matched,
        });
        i--;
        j--;
        continue;
      }
    }

    if (i > 0 && dp[i][j] === dp[i - 1][j] + 1) {
      alignment.unshift({
        type: "deletion",
        original: origWords[i - 1],
        recognized: null,
        correct: false,
      });
      i--;
      continue;
    }

    if (j > 0) {
      alignment.unshift({
        type: "insertion",
        original: null,
        recognized: recWords[j - 1],
        correct: false,
      });
      j--;
    }
  }

  return alignment;
}

export function countCorrectWords(alignment: AlignedWord[]): number {
  return alignment.filter((a) => a.correct).length;
}

export function countOriginalWords(alignment: AlignedWord[]): number {
  return alignment.filter((a) => a.original != null).length;
}

import { useCallback, useEffect, useRef, useState } from "react";
import { transcribeAudio } from "../lib/transcribe";

interface UseSpeechRecognitionReturn {
  supported: boolean;
  recording: boolean;
  transcript: string;
  error: string | null;
  start: () => void;
  stop: () => Promise<void>;
}

const env = typeof import.meta !== "undefined" ? import.meta.env : undefined;
const TRANSCRIBE_API_URL =
  (env?.VITE_TRANSCRIBE_API_URL as string | undefined) ?? "/api/transcribe";

function isBrowserSupported(): boolean {
  return (
    typeof navigator !== "undefined" &&
    typeof MediaRecorder !== "undefined" &&
    !!navigator.mediaDevices?.getUserMedia
  );
}

function selectMimeType(): string {
  const candidates = [
    "audio/webm;codecs=opus",
    "audio/webm",
    "audio/mp4",
    "audio/mp4;codecs=mp4a.40.2",
  ];
  for (const type of candidates) {
    if (MediaRecorder.isTypeSupported(type)) {
      return type;
    }
  }
  return "";
}

function getMicrophoneErrorMessage(error: unknown): string {
  if (error instanceof DOMException) {
    if (
      error.name === "NotAllowedError" ||
      error.name === "PermissionDeniedError"
    ) {
      return "Microphone access was denied. Please allow microphone permission and try again.";
    }
    if (
      error.name === "NotFoundError" ||
      error.name === "DevicesNotFoundError"
    ) {
      return "No microphone found. Please connect a microphone and try again.";
    }
  }
  return `Failed to access the microphone: ${error instanceof Error ? error.message : String(error)}`;
}

function getTranscriptionErrorMessage(error: unknown): string {
  return error instanceof Error
    ? error.message
    : "Transcription failed. Please try again.";
}

export function useSpeechRecognition(): UseSpeechRecognitionReturn {
  const [supported] = useState(() => isBrowserSupported());
  const [recording, setRecording] = useState(false);
  const [transcript, setTranscript] = useState("");
  const [error, setError] = useState<string | null>(null);

  const streamRef = useRef<MediaStream | null>(null);
  const recorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const stopPromiseRef = useRef<(() => void) | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  const finalizeStop = useCallback(() => {
    setRecording(false);
    stopPromiseRef.current?.();
    stopPromiseRef.current = null;
  }, []);

  const cleanup = useCallback(() => {
    abortControllerRef.current?.abort();
    abortControllerRef.current = null;

    const recorder = recorderRef.current;
    recorderRef.current = null;
    if (recorder) {
      try {
        recorder.stop();
      } catch {
        // ignore
      }
    }

    streamRef.current?.getTracks().forEach((track) => track.stop());
    streamRef.current = null;
    chunksRef.current = [];
  }, []);

  const start = useCallback(async () => {
    if (!supported) {
      setError("Microphone recording is not supported in this browser.");
      return;
    }

    cleanup();
    setTranscript("");
    setError(null);
    chunksRef.current = [];
    setRecording(true);

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const mimeType = selectMimeType();
      const recorder = new MediaRecorder(
        stream,
        mimeType ? { mimeType } : undefined,
      );
      recorderRef.current = recorder;

      recorder.addEventListener("dataavailable", (event) => {
        const data = (event as BlobEvent).data;
        if (data && data.size > 0) {
          chunksRef.current.push(data);
        }
      });

      recorder.addEventListener("error", (event) => {
        const recorderError = (event as Event & { error?: DOMException }).error;
        setError(getMicrophoneErrorMessage(recorderError));
        cleanup();
        finalizeStop();
      });

      recorder.addEventListener("stop", async () => {
        if (recorderRef.current !== recorder) {
          return;
        }

        stream.getTracks().forEach((track) => track.stop());

        const blob = new Blob(chunksRef.current, {
          type: recorder.mimeType || "audio/webm",
        });

        if (blob.size === 0) {
          setError("No audio recorded. Please try again.");
          finalizeStop();
          return;
        }

        const controller = new AbortController();
        abortControllerRef.current = controller;

        try {
          const text = await transcribeAudio(
            blob,
            TRANSCRIBE_API_URL,
            controller.signal,
          );
          setTranscript(text);
          finalizeStop();
        } catch (fetchError) {
          if ((fetchError as Error).name === "AbortError") {
            finalizeStop();
            return;
          }
          setError(getTranscriptionErrorMessage(fetchError));
          finalizeStop();
        } finally {
          abortControllerRef.current = null;
        }
      });

      recorder.start();
    } catch (micError) {
      setError(getMicrophoneErrorMessage(micError));
      setRecording(false);
    }
  }, [supported, cleanup, finalizeStop]);

  const stop = useCallback(() => {
    return new Promise<void>((resolve) => {
      const recorder = recorderRef.current;
      if (!recorder || recorder.state === "inactive") {
        resolve();
        return;
      }

      stopPromiseRef.current = resolve;
      try {
        recorder.stop();
      } catch {
        setRecording(false);
        resolve();
      }
    });
  }, []);

  useEffect(() => cleanup, [cleanup]);

  return { supported, recording, transcript, error, start, stop };
}

import { useCallback, useEffect, useRef, useState } from "react";

interface UseTtsReturn {
  playing: boolean;
  loading: boolean;
  error: string | null;
  currentTime: number;
  duration: number;
  playbackRate: number;
  setPlaybackRate: (rate: number) => void;
  play: (url: string, onEnded?: () => void) => Promise<void>;
  playSegments: (urls: string[], onEnded?: () => void) => Promise<void>;
  playSegmentsWithGaps: (urls: string[], gaps: number[]) => Promise<void>;
  pause: () => void;
  resume: () => void;
  stop: () => void;
  seek: (time: number) => void;
}

let sharedAudioCtx: AudioContext | null = null;

function getAudioContext(): AudioContext {
  if (!sharedAudioCtx) {
    sharedAudioCtx = new AudioContext();
  }
  return sharedAudioCtx;
}

async function fetchAndDecodeAudio(url: string): Promise<AudioBuffer> {
  const response = await fetch(url);
  if (!response.ok) {
    throw new Error(`Audio fetch failed (${response.status})`);
  }
  const arrayBuffer = await response.arrayBuffer();
  const ctx = getAudioContext();
  if (ctx.state === "suspended") {
    await ctx.resume();
  }
  return ctx.decodeAudioData(arrayBuffer.slice(0));
}

function createSilenceBuffer(
  durationSec: number,
  sampleRate: number,
  numberOfChannels: number,
): AudioBuffer {
  const ctx = getAudioContext();
  const length = Math.round(sampleRate * durationSec);
  return ctx.createBuffer(numberOfChannels, length, sampleRate);
}

function concatenateAudioBuffers(buffers: AudioBuffer[]): AudioBuffer {
  const totalLength = buffers.reduce((sum, buf) => sum + buf.length, 0);
  const sampleRate = buffers[0].sampleRate;
  const numberOfChannels = buffers[0].numberOfChannels;
  const ctx = getAudioContext();
  const result = ctx.createBuffer(numberOfChannels, totalLength, sampleRate);

  for (let channel = 0; channel < numberOfChannels; channel++) {
    const resultData = result.getChannelData(channel);
    let offset = 0;
    for (const buf of buffers) {
      resultData.set(buf.getChannelData(channel), offset);
      offset += buf.length;
    }
  }
  return result;
}

function audioBufferToWavBlob(buffer: AudioBuffer): Blob {
  const numChannels = buffer.numberOfChannels;
  const sampleRate = buffer.sampleRate;
  const bytesPerSample = 2;
  const blockAlign = numChannels * bytesPerSample;
  const dataLength = buffer.length * blockAlign;
  const headerLength = 44;
  const arrayBuffer = new ArrayBuffer(headerLength + dataLength);
  const view = new DataView(arrayBuffer);

  const writeString = (offset: number, str: string) => {
    for (let i = 0; i < str.length; i++) {
      view.setUint8(offset + i, str.charCodeAt(i));
    }
  };

  writeString(0, "RIFF");
  view.setUint32(4, 36 + dataLength, true);
  writeString(8, "WAVE");
  writeString(12, "fmt ");
  view.setUint32(16, 16, true);
  view.setUint16(20, 1, true);
  view.setUint16(22, numChannels, true);
  view.setUint32(24, sampleRate, true);
  view.setUint32(28, sampleRate * blockAlign, true);
  view.setUint16(32, blockAlign, true);
  view.setUint16(34, 16, true);
  writeString(36, "data");
  view.setUint32(40, dataLength, true);

  const offset = 44;
  for (let i = 0; i < buffer.length; i++) {
    for (let ch = 0; ch < numChannels; ch++) {
      const sample = Math.max(-1, Math.min(1, buffer.getChannelData(ch)[i]));
      const intSample = sample < 0 ? sample * 0x8000 : sample * 0x7fff;
      view.setInt16(
        offset + (i * numChannels + ch) * bytesPerSample,
        intSample,
        true,
      );
    }
  }

  return new Blob([arrayBuffer], { type: "audio/wav" });
}

export function useTts(): UseTtsReturn {
  const [playing, setPlaying] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const urlRef = useRef<string | null>(null);
  const rafRef = useRef<number>(0);
  const playbackRateRef = useRef(1.0);
  const [playbackRate, setPlaybackRateState] = useState(1.0);

  const cleanup = useCallback(() => {
    if (rafRef.current) {
      cancelAnimationFrame(rafRef.current);
      rafRef.current = 0;
    }
    if (audioRef.current) {
      const audio = audioRef.current;
      audio.pause();
      audio.onended = null;
      audio.onerror = null;
      audio.src = "";
      audioRef.current = null;
    }
    if (urlRef.current) {
      URL.revokeObjectURL(urlRef.current);
      urlRef.current = null;
    }
    onEndedRef.current = null;
    setPlaying(false);
    setLoading(false);
    setCurrentTime(0);
    setDuration(0);
  }, []);

  useEffect(() => {
    return () => cleanup();
  }, [cleanup]);

  const tick = useCallback(() => {
    if (audioRef.current) {
      setCurrentTime(audioRef.current.currentTime);
      setDuration(audioRef.current.duration || 0);
    }
    rafRef.current = requestAnimationFrame(tick);
  }, []);

  const onEndedRef = useRef<(() => void) | null>(null);

  const startPlayback = useCallback(
    async (url: string) => {
      const audio = new Audio(url);
      audio.playbackRate = playbackRateRef.current;
      audioRef.current = audio;
      audio.onended = () => {
        setPlaying(false);
        if (rafRef.current) {
          cancelAnimationFrame(rafRef.current);
          rafRef.current = 0;
        }
        onEndedRef.current?.();
        onEndedRef.current = null;
        // Release the audio element and blob URL so Safari can free the audio
        // session before speech recognition starts. Remove the error handler
        // first so clearing src does not fire a spurious error event.
        if (audioRef.current === audio) {
          audio.onerror = null;
          audio.pause();
          audio.src = "";
          audioRef.current = null;
          if (urlRef.current) {
            URL.revokeObjectURL(urlRef.current);
            urlRef.current = null;
          }
        }
        setCurrentTime(0);
        setDuration(0);
      };
      audio.onerror = () => {
        setPlaying(false);
        setError("Audio playback error");
        setLoading(false);
        onEndedRef.current = null;
        if (audioRef.current === audio) {
          audio.onended = null;
          audio.pause();
          audio.src = "";
          audioRef.current = null;
          if (urlRef.current) {
            URL.revokeObjectURL(urlRef.current);
            urlRef.current = null;
          }
        }
      };
      await audio.play();
      setPlaying(true);
      setLoading(false);
      rafRef.current = requestAnimationFrame(tick);
    },
    [tick],
  );

  const play = useCallback(
    async (url: string, onEnded?: () => void) => {
      cleanup();
      onEndedRef.current = onEnded ?? null;
      setError(null);
      setLoading(true);
      try {
        const response = await fetch(url);
        if (!response.ok) {
          throw new Error(`Audio fetch failed (${response.status})`);
        }
        const blob = await response.blob();
        const objectUrl = URL.createObjectURL(blob);
        urlRef.current = objectUrl;
        await startPlayback(objectUrl);
      } catch (e) {
        onEndedRef.current = null;
        setError(e instanceof Error ? e.message : String(e));
        setLoading(false);
      }
    },
    [cleanup, startPlayback],
  );

  const playSegments = useCallback(
    async (urls: string[], onEnded?: () => void) => {
      cleanup();
      onEndedRef.current = onEnded ?? null;
      setError(null);
      setLoading(true);
      try {
        const buffers = await Promise.all(
          urls.map((url) => fetchAndDecodeAudio(url)),
        );

        const combinedBuffer = concatenateAudioBuffers(buffers);
        const wavBlob = audioBufferToWavBlob(combinedBuffer);
        const url = URL.createObjectURL(wavBlob);
        urlRef.current = url;

        await startPlayback(url);
      } catch (e) {
        onEndedRef.current = null;
        setError(e instanceof Error ? e.message : String(e));
        setLoading(false);
      }
    },
    [cleanup, startPlayback],
  );

  const playSegmentsWithGaps = useCallback(
    async (urls: string[], gaps: number[]) => {
      cleanup();
      setError(null);
      setLoading(true);
      try {
        const buffers = await Promise.all(
          urls.map((url) => fetchAndDecodeAudio(url)),
        );

        const sampleRate = buffers[0].sampleRate;
        const numberOfChannels = buffers[0].numberOfChannels;
        const buffersWithSilence: AudioBuffer[] = [];

        for (let i = 0; i < buffers.length; i++) {
          buffersWithSilence.push(buffers[i]);
          const gap = gaps[i];
          if (gap !== undefined && gap > 0) {
            buffersWithSilence.push(
              createSilenceBuffer(gap, sampleRate, numberOfChannels),
            );
          }
        }

        const combinedBuffer = concatenateAudioBuffers(buffersWithSilence);
        const wavBlob = audioBufferToWavBlob(combinedBuffer);
        const url = URL.createObjectURL(wavBlob);
        urlRef.current = url;

        await startPlayback(url);
      } catch (e) {
        setError(e instanceof Error ? e.message : String(e));
        setLoading(false);
      }
    },
    [cleanup, startPlayback],
  );

  const pause = useCallback(() => {
    if (audioRef.current) {
      audioRef.current.pause();
      setPlaying(false);
      if (rafRef.current) {
        cancelAnimationFrame(rafRef.current);
        rafRef.current = 0;
      }
    }
  }, []);

  const resume = useCallback(() => {
    if (audioRef.current) {
      audioRef.current.playbackRate = playbackRateRef.current;
      audioRef.current
        .play()
        .then(() => {
          setPlaying(true);
          setError(null);
          if (!rafRef.current) {
            rafRef.current = requestAnimationFrame(tick);
          }
        })
        .catch(() => {
          setError("Resume failed");
        });
    }
  }, [tick]);

  const stop = useCallback(() => {
    cleanup();
  }, [cleanup]);

  const setPlaybackRate = useCallback((rate: number) => {
    const clamped = Math.min(rate, 1.5);
    playbackRateRef.current = clamped;
    setPlaybackRateState(clamped);
    if (audioRef.current) {
      audioRef.current.playbackRate = clamped;
    }
  }, []);

  const seek = useCallback((time: number) => {
    if (audioRef.current && Number.isFinite(time)) {
      const audio = audioRef.current;
      const maxTime = audio.duration || 0;
      audio.currentTime = Math.max(0, Math.min(time, maxTime));
      setCurrentTime(audio.currentTime);
    }
  }, []);

  return {
    playing,
    loading,
    error,
    currentTime,
    duration,
    playbackRate,
    setPlaybackRate,
    play,
    playSegments,
    playSegmentsWithGaps,
    pause,
    resume,
    stop,
    seek,
  };
}

import { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import { SectionHeader } from "../layout/SectionHeader";
import { Button } from "../ui/Button";
import { LoadingSpinner } from "../ui/LoadingSpinner";
import { type QuestionFileEntry, listQuestionFiles } from "../../lib/questions";
import {
  useScoreHistory,
  type ScoreEntry,
  type TaskId,
} from "../../hooks/useScoreHistory";
import { formatSecondsAsMmSs } from "../../lib/time";
import table from "../ui/ProblemTable.module.css";
import styles from "./QuestionSelectorPage.module.css";

interface QuestionSelectorPageProps {
  taskId: TaskId;
  title: string;
  subtitle: string;
  backTo: string;
  basePath: string;
}

function buildLatestByQuestionFile(
  entries: ScoreEntry[],
): Map<string, ScoreEntry> {
  const latestByFile = new Map<string, ScoreEntry>();
  entries.forEach((entry) => {
    if (!entry.questionFile) return;
    const existing = latestByFile.get(entry.questionFile);
    if (
      !existing ||
      new Date(existing.date).getTime() < new Date(entry.date).getTime()
    ) {
      latestByFile.set(entry.questionFile, entry);
    }
  });
  return latestByFile;
}

export function QuestionSelectorPage({
  taskId,
  title,
  subtitle,
  backTo,
  basePath,
}: QuestionSelectorPageProps) {
  const navigate = useNavigate();
  const { getAll } = useScoreHistory();
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [files, setFiles] = useState<QuestionFileEntry[]>([]);
  const [scores, setScores] = useState<ScoreEntry[]>([]);

  useEffect(() => {
    let active = true;

    Promise.all([listQuestionFiles(taskId), getAll()])
      .then(([questionFiles, allScores]) => {
        if (!active) return;
        setFiles(questionFiles);
        setScores(allScores.filter((entry) => entry.taskId === taskId));
        setError(null);
      })
      .catch((e) => {
        if (!active) return;
        setError(e instanceof Error ? e.message : String(e));
      })
      .finally(() => {
        if (!active) return;
        setLoading(false);
      });

    return () => {
      active = false;
    };
  }, [getAll, taskId]);

  const latestByFile = useMemo(
    () => buildLatestByQuestionFile(scores),
    [scores],
  );

  const handlePick = (questionNumber: number) => {
    navigate(`${basePath}/${questionNumber}`);
  };

  const handleRandom = () => {
    if (files.length === 0) return;
    const item = files[Math.floor(Math.random() * files.length)];
    handlePick(item.number);
  };

  return (
    <div>
      <SectionHeader title={title} subtitle={subtitle} backTo={backTo} />

      <div className={styles.topBar}>
        <Button
          variant="accent"
          onClick={handleRandom}
          disabled={loading || files.length === 0}
          size="md"
        >
          Pick Random
        </Button>
      </div>

      {loading && <LoadingSpinner message="Loading question list..." />}
      {error && (
        <div className={styles.error}>
          <p>{error}</p>
        </div>
      )}

      {!loading && !error && (
        <div className={table.container}>
          {files.map((item, i) => {
            const latest = latestByFile.get(item.file);
            const elapsed =
              typeof latest?.elapsedSeconds === "number"
                ? formatSecondsAsMmSs(latest.elapsedSeconds)
                : "—";
            const accuracy =
              typeof latest?.pct === "number" ? `${latest.pct}%` : "—";
            const completed = !!latest;

            return (
              <button
                type="button"
                key={item.file}
                className={[
                  table.row,
                  styles.row5Col,
                  completed ? table.rowCompleted : "",
                ].join(" ")}
                onClick={() => handlePick(item.number)}
              >
                <span className={table.statusCol}>
                  {completed ? (
                    <span className={table.statusSolved}>✓</span>
                  ) : (
                    <span className={table.statusNone}>{i + 1}</span>
                  )}
                </span>
                <span className={styles.number}>Q{item.number}</span>
                <span className={styles.metric}>
                  <span className={styles.metricLabel}>Time</span>
                  <span className={styles.metricValue}>{elapsed}</span>
                </span>
                <span className={styles.metric}>
                  <span className={styles.metricLabel}>Accuracy</span>
                  <span
                    className={[
                      styles.metricValue,
                      completed ? styles.metricValueAccent : "",
                    ].join(" ")}
                  >
                    {accuracy}
                  </span>
                </span>
                <span className={styles.chevron}>→</span>
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
}

import { useState, useEffect, useRef, useCallback } from "react";

export function useTimer(initialSeconds: number, onExpire?: () => void) {
  const [seconds, setSeconds] = useState(initialSeconds);
  const [running, setRunning] = useState(false);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const onExpireRef = useRef(onExpire);
  useEffect(() => {
    onExpireRef.current = onExpire;
  }, [onExpire]);

  const clear = useCallback(() => {
    if (intervalRef.current) {
      clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
  }, []);

  const start = useCallback(() => {
    setRunning(true);
  }, []);

  const stop = useCallback(() => {
    setRunning(false);
    clear();
  }, [clear]);

  const reset = useCallback(() => {
    stop();
    setSeconds(initialSeconds);
  }, [stop, initialSeconds]);

  useEffect(() => {
    if (!running) return;
    intervalRef.current = setInterval(() => {
      setSeconds((s) => {
        if (s <= 1) {
          clear();
          setRunning(false);
          onExpireRef.current?.();
          return 0;
        }
        return s - 1;
      });
    }, 1000);
    return clear;
  }, [running, clear]);

  const minutes = Math.floor(seconds / 60);
  const secs = seconds % 60;
  const display = `${String(minutes).padStart(2, "0")}:${String(secs).padStart(2, "0")}`;
  const isWarning = seconds <= 60 && seconds > 0;
  const isExpired = seconds === 0;

  return {
    seconds,
    display,
    isWarning,
    isExpired,
    running,
    start,
    stop,
    reset,
  };
}

import { useCallback, useEffect, useRef, useState } from "react";
import { formatSecondsAsMmSs } from "../lib/time";

export function useElapsedTimer() {
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const [running, setRunning] = useState(false);

  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const startedAtRef = useRef<number | null>(null);
  const baseSecondsRef = useRef(0);

  const clear = useCallback(() => {
    if (!intervalRef.current) return;
    clearInterval(intervalRef.current);
    intervalRef.current = null;
  }, []);

  const sync = useCallback(() => {
    if (startedAtRef.current == null) return baseSecondsRef.current;
    const total =
      baseSecondsRef.current +
      Math.floor((Date.now() - startedAtRef.current) / 1000);
    setElapsedSeconds(total);
    return total;
  }, []);

  const start = useCallback(() => {
    if (startedAtRef.current != null) return;
    startedAtRef.current = Date.now();
    setRunning(true);
    setElapsedSeconds(baseSecondsRef.current);
  }, []);

  const stop = useCallback(() => {
    if (startedAtRef.current == null) return baseSecondsRef.current;
    const total =
      baseSecondsRef.current +
      Math.floor((Date.now() - startedAtRef.current) / 1000);
    baseSecondsRef.current = total;
    startedAtRef.current = null;
    setElapsedSeconds(total);
    setRunning(false);
    clear();
    return total;
  }, [clear]);

  const reset = useCallback(() => {
    startedAtRef.current = null;
    baseSecondsRef.current = 0;
    setElapsedSeconds(0);
    setRunning(false);
    clear();
  }, [clear]);

  useEffect(() => {
    if (!running) return;
    intervalRef.current = setInterval(sync, 1000);
    sync();
    return clear;
  }, [running, sync, clear]);

  useEffect(() => clear, [clear]);

  return {
    elapsedSeconds,
    display: formatSecondsAsMmSs(elapsedSeconds),
    running,
    start,
    stop,
    reset,
  };
}

export function formatSecondsAsMmSs(seconds: number): string {
  const safeSeconds = Math.max(0, Math.floor(seconds));
  const minutes = Math.floor(safeSeconds / 60);
  const secs = safeSeconds % 60;
  return `${String(minutes).padStart(2, "0")}:${String(secs).padStart(2, "0")}`;
}

export async function transcribeAudio(
  audio: Blob,
  url: string,
  signal?: AbortSignal,
): Promise<string> {
  const formData = new FormData();
  formData.append("audio", audio, "recording.webm");

  const response = await fetch(url, {
    method: "POST",
    body: formData,
    signal,
  });

  if (!response.ok) {
    const body = (await response.json().catch(() => ({}))) as {
      error?: string;
    };
    throw new Error(
      body.error ?? `Transcription request failed (${response.status})`,
    );
  }

  const body = (await response.json()) as { text?: string };
  return body.text ?? "";
}

/// <reference types="@cloudflare/workers-types" />

interface Env {
  AI: Ai;
}

interface TranscriptionResponse {
  text: string;
}

const MAX_AUDIO_BYTES = 25 * 1024 * 1024; // 25 MB

function corsHeaders(): Record<string, string> {
  return {
    "Access-Control-Allow-Origin": "*",
    "Access-Control-Allow-Methods": "POST, OPTIONS",
    "Access-Control-Allow-Headers": "Content-Type",
  };
}

export const onRequestPost: PagesFunction<Env> = async (context) => {
  const request = context.request;

  try {
    const contentLength = Number(request.headers.get("Content-Length") ?? "0");
    if (contentLength > MAX_AUDIO_BYTES) {
      return Response.json(
        { error: "Audio file is too large." },
        { status: 413, headers: corsHeaders() },
      );
    }

    const formData = await request.formData();
    const audio = formData.get("audio");

    if (!(audio instanceof Blob) || audio.size === 0) {
      return Response.json(
        { error: "Missing audio file." },
        { status: 400, headers: corsHeaders() },
      );
    }

    const bytes = new Uint8Array(await audio.arrayBuffer());
    const result = await context.env.AI.run("@cf/openai/whisper", {
      audio: [...bytes],
      language: "en",
    });

    const text =
      result && typeof result === "object" && "text" in result
        ? String(result.text)
        : "";

    const responseBody: TranscriptionResponse = { text };
    return Response.json(responseBody, { headers: corsHeaders() });
  } catch (error) {
    const message =
      error instanceof Error ? error.message : "Transcription failed.";
    return Response.json(
      { error: message },
      { status: 500, headers: corsHeaders() },
    );
  }
};

export const onRequestOptions: PagesFunction<Env> = async () => {
  return new Response(null, {
    status: 204,
    headers: corsHeaders(),
  });
};

